resource "random_id" "suffix" {
  byte_length = 4
}

resource "random_password" "internal_db" {
  length  = 16
  special = false
}

resource "random_password" "public_db" {
  length  = 16
  special = false
}

# VPC for private and public subnets
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
}

# Public subnet
resource "aws_subnet" "public" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "us-west-2a"
  map_public_ip_on_launch = true
}

# Private subnet
resource "aws_subnet" "private" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-west-2a"
}

# Internet Gateway
resource "aws_internet_gateway" "main" {
  vpc_id = aws_vpc.main.id
}

# Public Route Table
resource "aws_route_table" "public" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.main.id
  }
}

resource "aws_route_table_association" "public" {
  subnet_id      = aws_subnet.public.id
  route_table_id = aws_route_table.public.id
}

# DB Subnet Group
resource "aws_db_subnet_group" "main" {
  name       = "main"
  subnet_ids = [aws_subnet.private.id, aws_subnet.public.id]
}

# Private RDS Instance (internal)
resource "aws_db_instance" "internal" {
  identifier              = "internal-${random_id.suffix.hex}"
  engine                  = "mysql"
  instance_class          = "db.t3.micro"
  allocated_storage       = 20
  db_subnet_group_name    = aws_db_subnet_group.main.name
  username                = "admin"
  password                = random_password.internal_db.result
  publicly_accessible     = false
  skip_final_snapshot     = true
  vpc_security_group_ids  = [aws_security_group.db.id]
}

# Public RDS Instance
resource "aws_db_instance" "public" {
  identifier              = "public-${random_id.suffix.hex}"
  engine                  = "mysql"
  instance_class          = "db.t3.micro"
  allocated_storage       = 20
  db_subnet_group_name    = aws_db_subnet_group.main.name
  username                = "admin"
  password                = random_password.public_db.result
  publicly_accessible     = true
  skip_final_snapshot     = true
  vpc_security_group_ids  = [aws_security_group.db.id]
}

# Security Group for RDS
resource "aws_security_group" "db" {
  vpc_id = aws_vpc.main.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16", "0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Public Hosted Zone
resource "aws_route53_zone" "public" {
  name = "example.com"
}

# Private Hosted Zone (associated with VPC)
resource "aws_route53_zone" "private" {
  name = "example.com"

  vpc {
    vpc_id = aws_vpc.main.id
  }
}

# A Record for internal users (private hosted zone) -> private RDS
resource "aws_route53_record" "internal" {
  zone_id = aws_route53_zone.private.zone_id
  name    = "db.internal.example.com"
  type    = "CNAME"
  ttl     = 300
  records = [aws_db_instance.internal.endpoint]
}

# A Record for external users (public hosted zone) -> public RDS
resource "aws_route53_record" "public" {
  zone_id = aws_route53_zone.public.zone_id
  name    = "db.public.example.com"
  type    = "CNAME"
  ttl     = 300
  records = [aws_db_instance.public.endpoint]
}

