resource "random_id" "suffix" {
  byte_length = 4
}

# IAM Role for EC2 instances in Elastic Beanstalk
resource "aws_iam_role" "eb_ec2_role" {
  name = "eb_ec2_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })
}

# Attach managed policies to the role
resource "aws_iam_role_policy_attachment" "eb_ec2_role_policy1" {
  role       = aws_iam_role.eb_ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWebTier"
}

resource "aws_iam_role_policy_attachment" "eb_ec2_role_policy2" {
  role       = aws_iam_role.eb_ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWorkerTier"
}

# Instance Profile for EC2
resource "aws_iam_instance_profile" "eb_ec2_profile" {
  name = "eb_ec2_profile"
  role = aws_iam_role.eb_ec2_role.name
}

# Elastic Beanstalk Application
resource "aws_elastic_beanstalk_application" "my_api_app" {
  name = "my_api_app"
}

# Elastic Beanstalk Launch Configuration
resource "aws_launch_configuration" "eb_launch_config" {
  name_prefix          = "eb-launch-${random_id.suffix.hex}"
  image_id             = "ami-0c02fb55956c7d316" # Amazon Linux 2 AMI (update as needed)
  instance_type        = "t3.micro"
  iam_instance_profile = aws_iam_instance_profile.eb_ec2_profile.name
  security_groups      = [] # Add your security group IDs here

  lifecycle {
    create_before_destroy = true
  }
}

# Auto Scaling Group
resource "aws_autoscaling_group" "eb_asg" {
  launch_configuration = aws_launch_configuration.eb_launch_config.name
  min_size             = 2
  max_size             = 4
  desired_capacity     = 2
  vpc_zone_identifier  = [] # Add your subnet IDs here

  tag {
    key                 = "Name"
    value               = "EB-ASG-${random_id.suffix.hex}"
    propagate_at_launch = true
  }
}

# CPU Utilization Scaling Policy (Scale Out)
resource "aws_autoscaling_policy" "scale_out" {
  name                   = "scale-out-cpu"
  scaling_adjustment     = 1
  adjustment_type        = "ChangeInCapacity"
  cooldown              = 300
  autoscaling_group_name = aws_autoscaling_group.eb_asg.name
}

# CPU Utilization Scaling Policy (Scale In)
resource "aws_autoscaling_policy" "scale_in" {
  name                   = "scale-in-cpu"
  scaling_adjustment     = -1
  adjustment_type        = "ChangeInCapacity"
  cooldown              = 300
  autoscaling_group_name = aws_autoscaling_group.eb_asg.name
}

# CloudWatch Alarm for High CPU (Scale Out)
resource "aws_cloudwatch_metric_alarm" "high_cpu" {
  alarm_name          = "high-cpu-${random_id.suffix.hex}"
  comparison_operator = "GreaterThanThreshold"
  evaluation_periods  = "2"
  metric_name         = "CPUUtilization"
  namespace           = "AWS/EC2"
  period              = "120"
  statistic           = "Average"
  threshold           = "70"
  alarm_actions       = [aws_autoscaling_policy.scale_out.arn]
  dimensions = {
