  role = aws_iam_role.eb_ec2_role.name
}

resource "aws_iam_role_policy" "eb_worker_policy" {
  name = "eb-worker-policy"
  role = aws_iam_role.eb_ec2_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "sqs:ReceiveMessage",
          "sqs:DeleteMessage",
          "sqs:GetQueueAttributes"
        ]
        Resource = aws_sqs_queue.batch_job_queue.arn
      },
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject"
        ]
        Resource = "${aws_s3_bucket.sample_bucket.arn}/*"
      }
    ]
  })
}

resource "aws_elastic_beanstalk_environment" "batch_worker" {
  name                = "batch-worker-env"
  application         = aws_elastic_beanstalk_application.batch_job_app.name
  solution_stack_name = "64bit Amazon Linux 2 v3.4.6 running Node.js 18"  # Example worker stack

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_ec2_profile.name
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "SQS_QUEUE_URL"
    value     = aws_sqs_queue.batch_job_queue.url
  }

  setting {
    namespace = "aws:elasticbeanstalk:workerqueue"
    name      = "QueueURL"
    value     = aws_sqs_queue.batch_job_queue.url
  }

  version_label = aws_elastic_beanstalk_application_version.version.name
}
