    name      = "InstanceType"
    value     = "t3.micro"
  }

  setting {
    namespace = "aws:ec2:vpc"
    name      = "VPCId"
    value     = data.aws_vpc.default.id
  }

  setting {
    namespace = "aws:ec2:vpc"
    name      = "Subnets"
    value     = join(",", data.aws_subnets.default.ids)
  }
}

# Route 53 Hosted Zone (assuming default zone)
data "aws_route53_zone" "main" {
  name = "example.com." # Replace with your domain
}

# Blue Route 53 Record with Weighted Routing (90% weight)
resource "aws_route53_record" "blue" {
  zone_id = data.aws_route53_zone.main.zone_id
  name    = "app.example.com" # Replace with your domain
  type    = "A"

  set_identifier = "blue"
  weighted_routing_policy {
    region          = data.aws_region.current.name
    failovers_routing_policy {
      type = "PRIMARY"
    }
  }

  aliases {
    name                   = aws_elastic_beanstalk_environment.blue.cname
    zone_id                = aws_elastic_beanstalk_environment.blue.dns_zone_id
    evaluate_target_health = false
  }
}

# Green Route 53 Record with Weighted Routing (10% weight)
resource "aws_route53_record" "green" {
  zone_id = data.aws_route53_zone.main.zone_id
  name    = "app.example.com" # Replace with your domain
  type    = "A"

  set_identifier = "green"
  weighted_routing_policy {
    region = data.aws_region.current.name
    failovers_routing_policy {
      type = "SECONDARY"
    }
  }

  aliases {
    name                   = aws_elastic_beanstalk_environment.green.cname
    zone_id                = aws_elastic_beanstalk_environment.green.dns_zone_id
    evaluate_target_health = false
  }
}

# Data sources for VPC and subnets (using default)
data "aws_vpc" "default" {
  default = true
}

data "aws_subnets" "default" {
  filter {
    name   = "vpc-id"
    values = [data.aws_vpc.default.id]
  }
}

data "aws_region" "current" {}
```

**Note:** Replace `"example.com"` with your actual hosted zone domain name. This configuration sets up Blue (90% traffic) as primary and Green (10% traffic) as secondary for canary testing in a Blue-Green deployment. Adjust weights as needed for traffic shifting.

