  name          = "sample-project"
  description   = "Sample CodeBuild project"
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "NO_ARTIFACTS"
  }

  cache {
    type  = "LOCAL"
    modes = ["LOCAL_DOCKER_LAYER_CACHE", "LOCAL_SOURCE_CACHE", "LOCAL_CUSTOM_CACHE"]
  }

  environment {
    compute_type    = "BUILD_GENERAL1_SMALL"
    image           = "aws/codebuild/standard:5.0"
    type            = "LINUX_CONTAINER"
    privileged_mode = true

    environment_variable {
      name  = "GITHUB_TOKEN"
      value = "your-github-token-here"
      type  = "PLAINTEXT"
    }

    environment_variable {
      name  = "APP_NAME"
      value = "sample-app"
      type  = "PLAINTEXT"
    }
  }

  source {
    type     = "GITHUB"
    location = "https://github.com/your-org/your-repo.git"
  }

  logs_config {
    cloudwatch_logs {
      group_name  = "/aws/codebuild/sample-project"
      stream_name = "sample-project-log"
    }
  }
}

