    buildspec = <<-EOF
      version: 0.2
      phases:
        build:
          commands:
            - echo "Building sample project"
            - mkdir -p primary-app test-reports
            - echo "app build" > primary-app/app.txt
            - echo "test results" > test-reports/results.txt
