}

resource "aws_s3_bucket_object" "primary_source_zip" {
  bucket = aws_s3_bucket.primary_source.id
  key    = "source.zip"
  source = "source.zip" # Assume local source.zip exists
}

# Secondary source repositories
resource "random_id" "suffix" {
  byte_length = 4
}

# Secondary source 1: CodeCommit
resource "aws_codecommit_repository" "secondary_repo1" {
  repository_name = "secondary-repo1-${random_id.suffix.hex}"
}

# Secondary source 2: GitHub (using connection)
resource "aws_codestarconnections_connection" "github" {
  name          = "github-connection-${random_id.suffix.hex}"
  provider_type = "GitHub"
}

# CodeBuild project
resource "aws_codebuild_project" "sample" {
  name          = "sample-project-${random_id.suffix.hex}"
  description   = "Sample CodeBuild project with multiple sources and artifacts"
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    name                      = "primary-artifact"
    type                      = "S3"
    location                  = aws_s3_bucket.primary_source.bucket
    namespace_type            = "NONE"
    packaging                 = "ZIP"
    override_artifact_name    = false
    encryption_disabled       = false
    artifact_identifier       = "primary"
  }

  secondary_artifacts {
    name              = "secondary1-artifact"
    type              = "S3"
    location          = aws_s3_bucket.primary_source.bucket
    packaging         = "ZIP"
    override_artifact_name = false
    encryption_disabled    = false
    artifact_identifier    = "secondary1"
  }

  secondary_artifacts {
    name              = "secondary2-artifact"
    type              = "S3"
    location          = aws_s3_bucket.primary_source.bucket
    packaging         = "ZIP"
    override_artifact_name = false
    encryption_disabled    = false
    artifact_identifier    = "secondary2"
  }

  source {
    type     = "S3"
    location = "${aws_s3_bucket.primary_source.bucket}/source.zip"
    buildspec = "buildspec.yml"
  }

  secondary_sources {
    source_identifier = "secondary1"
    type             = "CODECOMMIT"
    location         = aws_codecommit_repository.secondary_repo1.clone_url_http
  }

  secondary_sources {
    source_identifier = "secondary2"
    type              = "GITHUB"
    location          = "https://github.com/example/repo.git"
    auth {
      type            = "CODESTARCONNECTIONS"
      resource        = aws_codestarconnections_connection.github.arn
    }
  }

  environment {
    compute_type    = "BUILD_GENERAL1_SMALL"
    image           = "aws/codebuild/standard:5.0"
    type            = "LINUX_CONTAINER"

    environment_variable {
      name  = "APP_NAME"
      value = "sample-app"
    }

    environment_variable {
      name  = "ENVIRONMENT"
      value = "dev"
    }

    environment_variable {
      name  = "BUILD_NUMBER"
      value = "$(date +%Y-%m-%d-%H-%M-%S)"
    }
  }

  logs_config {
    cloudwatch_logs {
      group_name  = "/aws/codebuild/sample-project"
      stream_name = "sample-project"
    }
  }
}

