resource "aws_lex_bot" "pizza_ordering" {
  name                               = "PizzaOrderingBot"
  abort_statement {
    message {
      content    = "Thanks for using PizzaBot! Goodbye."
      content_type = "PlainText"
    }
  }

  intent {
    name = "OrderPizzaIntent"
    fulfillment_activity {
      code_hook {
        message_version = "1.0"
        uri             = "arn:aws:lambda:us-east-1:123456789012:function:PizzaOrderHandler"
      }
    }
    slot {
      name = "PizzaSize"
      slot_constraint       = "Required"
      slot_type             = "PizzaSize"
      value_elicitation_prompt {
        message {
          content    = "What size pizza would you like? Small, medium, or large?"
          content_type = "PlainText"
        }
      }
    }
    slot {
      name = "PizzaToppings"
      slot_constraint       = "Optional"
      slot_type             = "PizzaToppings"
      value_elicitation_prompt {
        message {
          content    = "What toppings would you like on your pizza?"
          content_type = "PlainText"
        }
      }
    }
    slot {
      name = "PizzaQuantity"
      slot_constraint       = "Required"
      slot_type             = "AMAZON.NUMBER"
      value_elicitation_prompt {
        message {
          content    = "How many pizzas would you like to order?"
          content_type = "PlainText"
        }
      }
    }
    sample_utterances = [
      "I want to order a pizza",
      "I'd like a pizza please",
      "Can I get a pizza",
      "Order pizza"
    ]
  }

  intent {
    name = "ConfirmOrderIntent"
    fulfillment_activity {
      type = "ReturnParameters"
    }
    sample_utterances = [
      "Yes that sounds good",
      "Confirm my order",
      "That's correct",
      "Yes please"
    ]
  }

  locale_configuration {
    locale              = "en_US"
    voice_id            = "Joanna"
    nlu_confidence_threshold = "0.75"
  }

  voice_id = "Joanna"

  clarification_statement {
    message {
      content    = "I didn't understand that. Can you rephrase?"
      content_type = "PlainText"
    }
  }
}

