resource "aws_lex_bot" "pizza_order_bot" {
  name                        = "PizzaOrderBotForKids"
  description                 = "Lex bot for children to place pizza orders"
  locale_configuration {
    locale           = "en_US"
    nlu_confidence_threshold = 0.75
  }
  voice_id          = "Joanna"
  abort_statement {
    message {
      content_type = "PlainText"
      content      = "Sorry, I didn't understand. Let's try again! Say 'pizza' to start."
    }
  }
  idle_session_ttl_in_seconds = 300

  intent {
    name = "PizzaOrderIntent"
    fulfillment_activity {
      type = "ReturnParameters"
    }
    slot {
      name {
        name = "PizzaSize"
        slot_type_id = aws_lex_slot_type.pizza_size.id
        priority = 1
      }
      prompt {
        message {
          content_type = "PlainText"
          content      = "What size pizza would you like? Small, medium, or large?"
        }
      }
      value_elicitation_prompt {
        message {
          content_type = "PlainText"
          content      = "Great! What size? Say small, medium, or large!"
        }
      }
    }
    slot {
      name {
        name = "PizzaToppings"
        slot_type_id = aws_lex_slot_type.pizza_toppings.id
        priority = 2
      }
      prompt {
        message {
          content_type = "PlainText"
          content      = "What toppings would you like? Pepperoni, cheese, or veggies?"
        }
      }
    }
    slot {
      name {
        name = "PizzaQuantity"
        slot_type_id = "AMAZON.NUMBER"
        priority = 3
      }
      prompt {
