# Lambda function for pizza order fulfillment
resource "aws_lambda_function" "pizza_fulfillment" {
  filename         = "pizza_handler.zip"  # Upload your Lambda code as pizza_handler.zip
  function_name    = "pizza-order-fulfillment-${random_id.suffix.hex}"
  role            = aws_iam_role.lambda_exec.arn
  handler         = "pizza_handler.lambda_handler"
