resource "aws_lex_bot" "pizza_order_bot" {
  name                               = "PizzaOrderBot-${random_id.suffix.hex}"
  description                        = "Bot for handling pizza orders"
  abort_statement {
    message {
      content    = "Sorry, I couldn't process your pizza order. Please try again."
      content_type = "PlainText"
    }
  }

  intent {
    name = "PizzaOrderIntent"

    slot {
      name         = "PizzaSize"
      slot_type    = aws_lex_slot_type.pizza_size.name
      slot_constraint = "Required"
      priority     = 1
      message {
        content    = "What size pizza would you like? Small, medium, or large?"
        content_type = "PlainText"
      }
    }

    slot {
      name         = "PizzaType"
      slot_type    = aws_lex_slot_type.pizza_type.name
      slot_constraint = "Required"
      priority     = 2
      message {
        content    = "What type of pizza? Pepperoni, cheese, or supreme?"
        content_type = "PlainText"
      }
    }

    slot {
      name         = "PizzaQuantity"
      slot_type    = "AMAZON.NUMBER"
      slot_constraint = "Required"
      priority     = 3
      message {
        content    = "How many pizzas would you like?"
        content_type = "PlainText"
      }
    }

    fulfillment_activity {
      type = "LambdaFulfillment"
      code_hook {
        message_version = "1.0"
        lambda_function_arn = aws_lambda_function.pizza_fulfillment.arn
      }
    }
  }

  voice_id = "Joanna"

  depends_on = [aws_lambda_function.pizza_fulfillment]
}

# Pizza size slot type
