  source = "flink-app.jar"  # Replace with path to your Flink application JAR
  etag   = filemd5("flink-app.jar")
}

resource "aws_kinesisanalyticsv2_application" "example" {
  name                   = "flink-app-${random_id.suffix.hex}"
  runtime_environment    = "FLINK-1_15"
  service_execution_role = aws_iam_role.analytics.arn
  start_application      = false

  application_configuration {
    flink_application_configuration {
      checkpoint_configuration {
        configuration_type       = "DEFAULT"
        checkpointing_enabled    = true
        checkpoint_interval      = 60000
        min_pause_between_checkpoints = 5000
      }

      monitoring_configuration {
        configuration_type       = "CUSTOM"
        log_level                = "INFO"
        metrics_level            = "TASK"
        vertex_log_level         = "INFO"
      }

      parallelism_configuration {
        configuration_type = "CUSTOM"
        parallelisms {
          min_parallelism = 1
          max_parallelism = 1
        }
      }
    }

    application_code_configuration {
      code_content {
        s3_content_location {
          bucket_arn = aws_s3_bucket.app_bucket.arn
          file_key   = aws_s3_object.flink_app.key
        }
      }
      code_content_type = "ZIPFILE"
    }

    environment_properties {
      property_group {
        property_group_id = "FlinkApplicationProperties"
        property_map = {
          "PropertyGroupId" = "example-property-group"
        }
      }
    }

    flink_run_configuration {
      allow_non_restored_state = false
    }
  }

  application_snapshot_configuration {
    snapshots_enabled = true
  }
}

resource "aws_iam_role" "analytics" {
  name = "kinesis-analytics-role-${random_id.suffix.hex}"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kinesisanalytics.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "analytics" {
  name = "kinesis-analytics-policy-${random_id.suffix.hex}"
  role = aws_iam_role.analytics.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "kinesis:*",
          "s3:GetObject",
          "s3:ListBucket",
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = [
          aws_kinesis_stream.input.arn,
          aws_s3_bucket.app_bucket.arn,
          "${aws_s3_bucket.app_bucket.arn}/*"
        ]
      }
    ]
  })
}
