  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
  tags = {
    Name = "kinesis-firehose-subnet-b-${random_id.suffix.hex}"
  }
}

resource "aws_security_group" "elasticsearch" {
  vpc_id = aws_vpc.main.id
  name   = "kinesis-firehose-es-sg-${random_id.suffix.hex}"

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.main.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "kinesis-firehose-es-sg-${random_id.suffix.hex}"
  }
}

resource "aws_elasticsearch_domain" "example" {
  domain_name           = "kinesis-firehose-es-${random_id.suffix.hex}"
  elasticsearch_version = "7.10"

  vpc_options {
    subnet_ids         = [aws_subnet.private_a.id, aws_subnet.private_b.id]
    security_group_ids = [aws_security_group.elasticsearch.id]
  }

  ebs_options {
    ebs_enabled = true
    volume_size = 10
  }

  access_policies = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          AWS = "*"
        }
        Action   = "es:*"
        Resource = "arn:aws:es:us-east-1:*:domain/kinesis-firehose-es-${random_id.suffix.hex}/*"
      }
    ]
  })

  tags = {
    Domain = "kinesis-firehose-es-${random_id.suffix.hex}"
  }
}

resource "aws_kinesis_firehose_delivery_stream" "elasticsearch" {
  name = "kinesis-firehose-to-es-${random_id.suffix.hex}"

  destination {
    elasticsearch_configuration {
      domain_arn        = aws_elasticsearch_domain.example.arn
      role_arn          = aws_iam_role.firehose_role.arn
      index_name        = "kinesis-firehose-index"
      type_name         = "_doc"
      retry_duration    = 300
      buffering_size    = 5
      buffering_interval = 300
      s3_backup_mode    = "FailedDataOnly"
    }
  }

  server_side_encryption {
    enabled  = true
    key_arn  = aws_kms_key.firehose.arn
  }

  vpc_configuration {
    role_arn           = aws_iam_role.firehose_vpc_role.arn
    subnet_ids         = [aws_subnet.private_a.id, aws_subnet.private_b.id]
    security_group_ids = [aws_security_group.elasticsearch.id]
  }
}

resource "aws_iam_role" "firehose_role" {
  name = "kinesis-firehose-role-${random_id.suffix.hex}"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "firehose_es_policy" {
  name = "kinesis-firehose-es-policy-${random_id.suffix.hex}"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "es:ESHttpPut",
          "es:ESHttpPost",
          "es:DescribeElasticsearchDomain"
        ]
        Resource = [
          aws_elasticsearch_domain.example.arn,
          "${aws_elasticsearch_domain.example.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Resource = [
          aws_s3_bucket.firehose_backup.arn,
          "${aws_s3_bucket.firehose_backup.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "kms:Decrypt",
          "kms:GenerateDataKey"
        ]
        Resource = aws_kms_key.firehose.arn
      }
    ]
  })
}

resource "aws_iam_role" "firehose_vpc_role" {
  name = "kinesis-firehose-vpc-role-${random_id.suffix.hex}"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "firehose_vpc_policy" {
  name = "kinesis-firehose-vpc-policy-${random_id.suffix.hex}"
  role = aws_iam_role.firehose_vpc_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "ec2:DescribeVpcs",
          "ec2:DescribeRouteTables",
          "ec2:DescribeSubnets",
          "ec2:DescribeSecurityGroups"
        ]
        Resource = "*"
      }
    ]
  })
}

resource "aws_s3_bucket" "firehose_backup" {
  bucket = "kinesis-firehose-backup-${random_id.suffix.hex}"
}

resource "aws_kms_key" "firehose" {
  description             = "KMS key for Kinesis Firehose"
  deletion_window_in_days = 7
}

resource "aws_kms_alias" "firehose" {
  name          = "alias/kinesis-firehose-${random_id.suffix.hex}"
  target_key_id = aws_kms_key.firehose.key_id
}
