    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "ec2-private-security-group"
  }
}

# EFS File System
resource "aws_efs_file_system" "shared" {
  encrypted = true
  tags = {
    Name = "shared-efs"
  }
}

resource "aws_efs_mount_target" "shared" {
  count           = 2
  file_system_id  = aws_efs_file_system.shared.id
  subnet_id       = aws_subnet.private.id
  security_groups = [aws_security_group.efs.id]
}

# Latest Amazon Linux 2 AMI (data source for latest)
data "aws_ami" "amazon_linux_2" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["amzn2-ami-hvm-*-x86_64-gp2"]
  }

  filter {
    name   = "virtualization-type"
    values = ["hvm"]
  }
}

# EC2 Instances
resource "aws_instance" "private" {
  count         = 2
  ami           = data.aws_ami.amazon_linux_2.id
  instance_type = "t3.micro"

  subnet_id              = aws_subnet.private.id
  vpc_security_group_ids = [aws_security_group.ec2.id]
  iam_instance_profile   = aws_iam_instance_profile.efs.id

  user_data = <<-EOF
    #!/bin/bash
    yum update -y
    yum install -y amazon-efs-utils
    mkdir /mnt/efs
    mount -t efs ${aws_efs_file_system.shared.id}:/ /mnt/efs
    echo "${aws_efs_file_system.shared.id}:/ /mnt/efs efs defaults,_netdev 0 0" >> /etc/fstab
  EOF

  tags = {
    Name = "private-ec2-${count.index + 1}"
  }
}

# IAM Role for EC2 to access EFS
resource "aws_iam_role" "ec2_efs" {
  name = "ec2-efs-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "ec2_efs" {
  role       = aws_iam_role.ec2_efs.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonEFSFullAccess"
}

resource "aws_iam_instance_profile" "efs" {
  name = "ec2-efs-profile"
  role = aws_iam_role.ec2_efs.name
}

