        Name = "input_data"
        Type = "String"
        DefaultValue = "s3://bucket/input/"
      },
      {
        Name = "model_output_path"
        Type = "String"
        DefaultValue = "s3://bucket/output/model/"
      },
      {
        Name = "bucket"
        Type = "String"
        DefaultValue = "my-bucket"
      }
    ]

    Steps = [
      {
        Name = "ProcessingStep"
        Type = "Processing"
        Arguments = {
          ProcessingOutputConfig = {
            Outputs = [
              {
                OutputName = "train_data"
                S3Output = {
                  S3Uri = "$${bucket}/output/train_data"
                  LocalPath = "/opt/ml/processing/output/train/"
                  S3UploadMode = "EndOfJob"
                }
              },
              {
                OutputName = "test_data"
                S3Output = {
                  S3Uri = "$${bucket}/output/test_data"
                  LocalPath = "/opt/ml/processing/output/test/"
                  S3UploadMode = "EndOfJob"
                }
              }
            ]
          }
          AppSpecification = {
            ImageUri = "683313688378.dkr.ecr.us-east-1.amazonaws.com/sagemaker-scikit-learn:0.23-1-cpu-py36"
            ContainerEntrypoint = ["/bin/bash"]
            ContainerArguments = ["/opt/ml/processing/entrypoint.sh"]
          }
          ProcessingResources = {
            ClusterConfig = {
              InstanceCount = 1
              InstanceType = "ml.m5.large"
              VolumeSizeInGB = 30
            }
          }
          ProcessingInputs = [
            {
              InputName = "raw_data"
              S3Input = {
                S3Uri = "$${input_data}"
                LocalPath = "/opt/ml/processing/input/"
                S3DataType = "S3Prefix"
                S3InputMode = "File"
                S3DataDistributionType = "FullyReplicated"
              }
            }
          ]
        }
      },
      {
        Name = "TrainingStep"
        Type = "Training"
        Arguments = {
          AlgorithmSpecification = {
            TrainingImage = "683313688378.dkr.ecr.us-east-1.amazonaws.com/sagemaker-xgboost:1.2-2-cpu-py3"
            TrainingInputMode = "File"
          }
          OutputDataConfig = {
            S3OutputPath = "$${model_output_path}"
          }
          StoppingCondition = {
            MaxRuntimeInSeconds = 3600
          }
          ResourceConfig = {
            InstanceCount = 1
            InstanceType = "ml.m5.xlarge"
            VolumeSizeInGB = 30
          }
          InputDataConfig = [
            {
              ChannelName = "train"
              DataSource = {
                S3DataSource = {
                  S3Uri = "$${bucket}/output/train_data"
                  S3DataType = "S3Prefix"
                  S3InputMode = "File"
                  S3DataDistributionType = "FullyReplicated"
                }
              }
              CompressionType = "None"
              ContentType = "text/csv"
            }
          ]
          HyperParameters = {
            max_depth = "5"
            eta = "0.2"
            gamma = "4"
            min_child_weight = "6"
            subsample = "0.8"
            objective = "binary:logistic"
            eval_metric = "error"
            num_round = "100"
          }
          RoleArn = "arn:aws:iam::123456789012:role/SageMakerRole"
        }
      }
    ]
  })

  role_arn = "arn:aws:iam::123456789012:role/SageMakerExecutionRole"
}

