  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.main.id
  }
}

resource "aws_route_table_association" "public" {
  subnet_id      = aws_subnet.public.id
  route_table_id = aws_route_table.public.id
}

resource "aws_default_route_table" "private" {
  default_route_table_id = aws_vpc.main.default_route_table_id
}

# Latest Amazon Linux 2 AMI data source
data "aws_ami" "amazon_linux_2" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["amzn2-ami-hvm-*-x86_64-gp2"]
  }

  filter {
    name   = "virtualization-type"
    values = ["hvm"]
  }
}

# Launch template for EC2 Fleet
resource "aws_launch_template" "fleet" {
  name_prefix   = "ec2-fleet-"
  image_id      = data.aws_ami.amazon_linux_2.id
  instance_type = "t3.medium"

  vpc_security_group_ids = [aws_security_group.fleet.id]

  user_data = base64encode(<<-EOF
    #!/bin/bash
    yum update -y
    EOF
  )

  tag_specifications {
    resource_type = "instance"
    tags = {
      Name = "ec2-fleet-instance"
    }
  }
}

# Security group for instances
resource "aws_security_group" "fleet" {
  name_prefix = "ec2-fleet-"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# EC2 Fleet with 5 On-Demand and 4 Spot instances
resource "aws_ec2_fleet" "example" {
  target_capacity_specification {
    total_target_capacity = 9
    on_demand_target_capacity = 5
    spot_target_capacity = 4
    default_target_capacity_type = "spot"
  }

  launch_template_config {
    launch_template_specification {
      launch_template_id      = aws_launch_template.fleet.id
      launch_template_name    = aws_launch_template.fleet.name
      version                 = aws_launch_template.fleet.latest_version
    }

    override {
      subnet_id = aws_subnet.public.id
      instance_type = "t3.medium"
    }

    override {
      subnet_id = aws_subnet.private.id
      instance_type = "t3.medium"
    }
  }

  type = "maintain"

  depends_on = [
    aws_internet_gateway.main,
    aws_route_table_association.public
  ]
}

