resource "aws_route_table" "private" {
  vpc_id = aws_vpc.main.id
  route {
    cidr_block     = "0.0.0.0/0"
    nat_gateway_id = aws_nat_gateway.main.id
  }
  tags = {
    Name = "private-rt"
  }
}

resource "aws_route_table_association" "private_1" {
  subnet_id      = aws_subnet.private_1.id
  route_table_id = aws_route_table.private.id
}

resource "aws_route_table_association" "private_2" {
  subnet_id      = aws_subnet.private_2.id
  route_table_id = aws_route_table.private.id
}

# Security Groups
resource "aws_security_group" "efs" {
  name_prefix = "efs-sg"
  vpc_id      = aws_vpc.main.id

  ingress {
    description     = "NFS from EC2 instances"
    from_port       = 2049
    to_port         = 2049
    protocol        = "tcp"
    self            = true
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "efs-sg"
  }
}

resource "aws_security_group" "ec2" {
  name_prefix = "ec2-private-sg"
  vpc_id      = aws_vpc.main.id

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "ec2-private-sg"
  }
}

# EFS File System
resource "aws_efs_file_system" "shared" {
  encrypted = true

  tags = {
    Name = "shared-efs"
  }
}

# EFS Mount Targets (in private subnets)
resource "aws_efs_mount_target" "private_1" {
  file_system_id  = aws_efs_file_system.shared.id
  subnet_id       = aws_subnet.private_1.id
  security_groups = [aws_security_group.efs.id]
}

resource "aws_efs_mount_target" "private_2" {
  file_system_id  = aws_efs_file_system.shared.id
  subnet_id       = aws_subnet.private_2.id
  security_groups = [aws_security_group.efs.id]
}

# EC2 Instances (Amazon Linux 2023)
resource "aws_instance" "private_1" {
  ami                    = "ami-0eafecddb14efcb37" # Amazon Linux 2023 us-west-2
  instance_type          = "t3.micro"
  subnet_id              = aws_subnet.private_1.id
  vpc_security_group_ids = [aws_security_group.ec2.id]
  iam_instance_profile   = aws_iam_instance_profile.efs.name

  user_data = <<-EOF
              #!/bin/bash
              yum update -y
              yum install -y amazon-efs-utils
              mkdir /mnt/efs
              mount -t efs ${aws_efs_file_system.shared.id}:/ /mnt/efs
              echo "${aws_efs_file_system.shared.id}:/ /mnt/efs amazon-efs-utils defaults,_netdev 0 0" >> /etc/fstab
              EOF

  tags = {
    Name = "efs-private-instance-1"
  }
}

resource "aws_instance" "private_2" {
  ami                    = "ami-0eafecddb14efcb37" # Amazon Linux 2023 us-west-2
  instance_type          = "t3.micro"
  subnet_id              = aws_subnet.private_2.id
  vpc_security_group_ids = [aws_security_group.ec2.id]
  iam_instance_profile   = aws_iam_instance_profile.efs.name

  user_data = <<-EOF
              #!/bin/bash
              yum update -y
              yum install -y amazon-efs-utils
              mkdir /mnt/efs
              mount -t efs ${aws_efs_file_system.shared.id}:/ /mnt/efs
              echo "${aws_efs_file_system.shared.id}:/ /mnt/efs amazon-efs-utils defaults,_netdev 0 0" >> /etc/fstab
              EOF

  tags = {
    Name = "efs-private-instance-2"
  }
}

# IAM Role for EFS access
resource "aws_iam_role" "efs" {
  name = "efs-access-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "efs" {
  role       = aws_iam_role.efs.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonEFSFullAccess"
}

resource "aws_iam_instance_profile" "efs" {
  name = "efs-access-profile"
  role = aws_iam_role.efs.name
}
```

