    ebs_volume_size = 100    # GB
    client_subnets = ["subnet-12345678", "subnet-87654321", "subnet-abcdef12"]  # Replace with your subnet IDs
    security_groups = ["sg-1234567890abcdef0"]  # Replace with your security group ID
  }

  encryption_info {
    encryption_at_rest_kms_key_arn = aws_kms_key.msk.arn
  }

  logging_info {
    broker_logs {
      s3 {
        bucket       = aws_s3_bucket.msk_logs.id
        prefix       = "logs/"
        enabled      = true
      }
    }
  }

  client_authentication {
    saslauth {
      enabled = true
    }
  }

  monitoring_info {
    cloudwatch_log_group = "/aws/msk/example-cluster"
  }
}
