            }

            scale_out_policy {
                cpu_utilization_percentage = 80
            }
        }
    }

    connector_configuration = {
        # modify the following connector class according to your code
        # the connector code depends on your msk setting
        # we will not provide an example connector code here
        "connector.class" = "com.github.xxx.kafka.connect.simulator.SimulatorSinkConnector"
        "tasks.max" = "1"
        "topics" = "example"
    }

    kafka_cluster {
        apache_kafka_cluster {
            bootstrap_servers = aws_msk_cluster.example.bootstrap_brokers_tls

            vpc {
                security_groups = [aws_security_group.sg.id]
                subnets = [aws_subnet.subnet_az1.id, 
                           aws_subnet.subnet_az2.id, 
                           aws_subnet.subnet_az3.id]
            }
        }
    }

    kafka_cluster_client_authentication {
        authentication_type = "NONE"
    }

    kafka_cluster_encryption_in_transit {
        encryption_type = "PLAINTEXT"
    }

    plugin {
        custom_plugin {
            arn = aws_mskconnect_custom_plugin.example.arn
            revision = aws_mskconnect_custom_plugin.example.latest_revision
        }
    }

    service_execution_role_arn = aws_iam_role.aws_msk_connector_role.arn
}

response:
```hcl
# Random suffix for unique naming
resource "random_id" "suffix" {
  byte_length = 4
}

# MSK Cluster in us-east-1 with 3 brokers
resource "aws_msk_cluster" "example" {
  cluster_name           = "msk-cluster-${random_id.suffix.hex}"
  kafka_version          = "2.8.1"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type   = "kafka.m5.large"
    ebs_volume_size = 100    # GB
    client_subnets = ["subnet-12345678", "subnet-87654321", "subnet-abcdef12"]  # Replace with your subnet IDs
    security_groups = ["sg-12345678"]  # Replace with your security group ID
  }

  vpc_config {
    subnet_ids         = ["subnet-12345678", "subnet-87654321", "subnet-abcdef12"]  # Replace with your subnet IDs
    security_group_ids = ["sg-12345678"]  # Replace with your security group ID
  }

  # Enable public access for simplicity (use VPC endpoints in production)
  client_authentication {
    sasl {
      scram512_kaecefams = []
    }
  }

  tags = {
    Name = "msk-cluster-${random_id.suffix.hex}"
  }
}

# IAM role for MSK Connect
resource "aws_iam_role" "msk_connect_role" {
  name = "msk-connect-role-${random_id.suffix.hex}"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kafkaconnect.amazonaws.com"
        }
      }
    ]
  })
}

# MSK Connect Custom Plugin from debezium.zip
resource "aws_mskconnect_custom_plugin" "debezium" {
  name       = "debezium-plugin-${random_id.suffix.hex}"
  description = "Debezium connector plugin"

  content_base64 = filebase64("debezium.zip")  # Place debezium.zip in your working directory
  location {
    s3 {
      bucket_arn = "arn:aws:s3:::your-bucket-name"  # Replace with your S3 bucket
      file_key   = "debezium.zip"
    }
  }
}

# MSK Connect Worker Configuration
resource "aws_mskconnect_worker_configuration" "example" {
  name = "worker-config-${random_id.suffix.hex}"

  properties = {
    "kafka.api.auth.oauth.token.endpoint.url" = "https://example.com"
  }
}

# MSK Connect Connector using Debezium plugin
resource "aws_mskconnect_connector" "debezium_connector" {
  connector_name = "debezium-connector-${random_id.suffix.hex}"

  kafka_cluster {
    apache_kafka_cluster {
      vpc {
        security_groups = ["sg-12345678"]  # Replace with your security group ID
        subnets         = ["subnet-12345678", "subnet-87654321"]  # Replace with your subnet IDs
      }
      kafka_cluster_ref {
        arn = aws_msk_cluster.example.arn
      }
    }
  }

  capacity {
    autoscaling {
      mcu_count        = 1
      min_worker_count = 1
      max_worker_count = 4
      scale_in_policy {
        cpu_utilization_percentage = 20
      }
      scale_out_policy {
        cpu_utilization_percentage = 80
      }
    }
  }

  connector_configuration = {
    "connector.class"               = "io.debezium.connector.mysql.MySqlConnector"
    "database.hostname"             = "your-mysql-host"  # Replace with your MySQL host
    "database.port"                 = "3306"
    "database.user"                 = "debezium"
    "database.password"             = "your-password"    # Use secrets manager in production
    "database.server.id"            = "184054"
    "database.server.name"          = "mysql-server"
    "database.include.list"         = "inventory"
    "database.history.kafka.bootstrap.servers" = aws_msk_cluster.example.bootstrap_brokers_tls[0]
    "database.history.kafka.topic"  = "dbhistory.inventory"
    "key.converter"                 = "org.apache.kafka.connect.json.JsonConverter"
    "value.converter"               = "io.debezium.converters.BytesConverter"
    "value.converter.type"          = "io.debezium.converters.BytesConverter"
    "value.converter.configs"       = "length.prefix=1"
  }

  kafka_connect_version = "2.7.1"
  plugins {
    custom_plugin {
      arn = aws_mskconnect_custom_plugin.debezium.arn
    }
  }

  service_execution_role_arn = aws_iam_role.msk_connect_role.arn
  worker_configuration {
    arn = aws_mskconnect_worker_configuration.example.arn
  }

  depends_on = [
    aws_msk_cluster.example,
    aws_mskconnect_custom_plugin.debezium
  ]
}

# Output cluster endpoint
output "msk_bootstrap_brokers_tls" {
  value = aws_msk_cluster.example.bootstrap_brokers_tls
}

output "connector_arn" {
  value = aws_mskconnect_connector.debezium_connector.arn
}
```

**Important Notes:**
1. Replace `subnet-xxx`, `sg-xxx`, and S3 bucket ARN with your actual VPC resources
2. Place `debezium.zip` in your Terraform working directory or update the S3 location
3. Update MySQL connection details in `connector_configuration`
4. In production, use AWS Secrets Manager for credentials and proper IAM policies for the MSK Connect role
5. Ensure your subnets are in `us-east-1` and have proper route tables for MSK

