```hcl
# Random suffix for unique naming
resource "random_id" "suffix" {
  byte_length = 4
}

# CloudWatch Logs group for MSK logs
resource "aws_cloudwatch_log_group" "msk_logs" {
  name              = "/aws/msk/cluster/${random_id.suffix.hex}"
  retention_in_days = 7
}

# S3 bucket for MSK logs
resource "aws_s3_bucket" "msk_logs" {
  bucket = "msk-logs-${random_id.suffix.hex}"
}

resource "aws_s3_bucket_server_side_encryption_configuration" "msk_logs" {
  bucket = aws_s3_bucket.msk_logs.bucket

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

resource "aws_s3_bucket_public_access_block" "msk_logs" {
  bucket = aws_s3_bucket.msk_logs.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# Kinesis Firehose delivery stream for MSK logs
resource "aws_kinesis_firehose_delivery_stream" "msk_logs" {
  name        = "msk-logs-firehose-${random_id.suffix.hex}"
  destination = "s3"

  s3_configuration {
    role_arn   = aws_iam_role.firehose_role.arn
    bucket_arn = aws_s3_bucket.msk_logs.arn
    prefix     = "firehose/"
  }
}

# IAM role for Firehose
resource "aws_iam_role" "firehose_role" {
  name = "firehose-role-${random_id.suffix.hex}"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "firehose_policy" {
  name = "firehose-policy-${random_id.suffix.hex}"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Effect = "Allow"
        Resource = [
          aws_s3_bucket.msk_logs.arn,
          "${aws_s3_bucket.msk_logs.arn}/*"
        ]
      }
    ]
  })
}

# MSK Cluster
resource "aws_msk_cluster" "example" {
  cluster_name           = "msk-cluster-${random_id.suffix.hex}"
  kafka_version          = "3.5.1"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type  = "kafka.m5.large"
    ebs_volume_size = 1000 # GB
    client_subnets = ["subnet-12345678", "subnet-87654321", "subnet-abcdef12"] # Replace with your subnet IDs
    security_groups = ["sg-12345678"] # Replace with your security group ID
  }

  encryption_info {
    encryption_at_rest {
      data_volume_kms_key_id = "arn:aws:kms:us-east-1:123456789012:key/1234abcd-12ab-34cd-56ef-1234567890ab" # Replace with your KMS key
    }
  }

  open_monitoring {
    prometheus {
      jmx_exporter {
        enabled_in_broker = true
      }
      node_exporter {
        enabled_in_broker = true
      }
    }
  }

  logging_info {
    broker_logs {
      cloudwatch_logs {
        enabled = true
        log_group = aws_cloudwatch_log_group.msk_logs.name
      }
      s3 {
        enabled = true
        bucket  = aws_s3_bucket.msk_logs.bucket
        prefix  = "logs/"
      }
      firehose {
        enabled = true
        delivery_stream = aws_kinesis_firehose_delivery_stream.msk_logs.name
      }
    }
  }

  # Replace with your VPC ID
  vpc_config {
    subnet_ids         = ["subnet-12345678", "subnet-87654321", "subnet-abcdef12"]
    security_group_ids = ["sg-12345678"]
  }
}

# MSK Connect Custom Plugin
resource "aws_mskconnect_custom_plugin" "debezium" {
  name       = "debezium-plugin-${random_id.suffix.hex}"
  description = "Debezium connector plugin"
  content_base64 = filebase64("debezium.zip") # Upload debezium.zip to your working directory
}

# IAM role for MSK Connect
resource "aws_iam_role" "mskconnect_role" {
  name = "mskconnect-role-${random_id.suffix.hex}"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kafkaconnect.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "mskconnect_policy" {
  role       = aws_iam_role.mskconnect_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AmazonMSKConnectServiceRolePolicy"
}

# MSK Connect Connector
resource "aws_mskconnect_connector" "debezium_connector" {
  connector_name = "debezium-connector-${random_id.suffix.hex}"
  kafka_cluster {
    apache_kafka_cluster {
      vpc {
        security_groups = ["sg-12345678"] # Replace with MSK security group
        subnets         = ["subnet-12345678", "subnet-87654321", "subnet-abcdef12"]
      }
      apache_kafka_cluster_arn = aws_msk_cluster.example.arn
    }
  }
  service_execution_role_arn = aws_iam_role.mskconnect_role.arn
  capacity {
    provisioned_capacity {
      mku_count = 1
    }
  }
  plugin {
    custom_plugin {
      arn = aws_mskconnect_custom_plugin.debezium.arn
    }
  }

  # Debezium connector configuration (example for MySQL source)
  kafka_connect_connector_configuration = {
    connector.class = "io.debezium.connector.mysql.MySqlConnector"
    tasks.max = "1"
    database.hostname = "your-mysql-host"
    database.port = "3306"
    database.user = "debezium"
    database.password = "password"
    database.server.id = "184054"
    database.server.name = "mysql1"
    database.include.list = "inventory"
    database.history.kafka.bootstrap.servers = aws_msk_cluster.example.bootstrap_brokers_tls
    database.history.kafka.topic = "dbhistory.mysql1"
    key.converter = "org.apache.kafka.connect.json.JsonConverter"
    value.converter = "io.debezium.converters.JsonConverter"
    value.converter.type = "io.debezium.converters.JsonConverter"
    value.converter.schemas.enable.schemas.registry = false
  }

  depends_on = [aws_msk_cluster.example]
}
```

**Important Notes:**
1. Replace placeholder subnet IDs, security group IDs, VPC ID, and KMS key ARN with your actual values
2. Download `debezium.zip` and place it in your Terraform working directory
3. Update the Debezium connector configuration with your source database details
4. Ensure your AWS provider is configured with appropriate permissions for MSK, MSK Connect, CloudWatch, S3, Kinesis, and IAM
5. The cluster will take 15-20 minutes to provision

