  availability_zone = "us-east-1a"
}

resource "aws_route_table" "neptune" {
  vpc_id = aws_vpc.neptune.id
}

resource "aws_route_table_association" "neptune" {
  subnet_id      = aws_subnet.neptune.id
  route_table_id = aws_route_table.neptune.id
}

# Custom cluster parameter group
resource "aws_neptune_cluster_parameter_group" "custom" {
  family = "neptune1"

  parameter {
    name  = "neptune_enable_audit_log"
    value = "1"
  }
}

# Custom instance parameter group
resource "aws_neptune_parameter_group" "custom" {
  family = "neptune1"

  parameter {
    name  = "neptune_query_timeout"
    value = "60000"
  }
}

# Neptune cluster
resource "aws_neptune_cluster" "example" {
  cluster_identifier              = "neptune-cluster-${random_id.suffix.hex}"
  engine                          = "neptune"
  backup_retention_period         = 1
  preferred_backup_window         = "07:00-09:00"
  skip_final_snapshot             = true
  iam_database_authentication_enabled = true

  cluster_parameter_group_name = aws_neptune_cluster_parameter_group.custom.id
  apply_immediately           = true
}

# Neptune cluster instance
resource "aws_neptune_cluster_instance" "example" {
  identifier         = "neptune-instance-${random_id.suffix.hex}"
  cluster_identifier = aws_neptune_cluster.example.id
  instance_class     = "db.t3.medium"
  engine             = "neptune"
  preferred_maintenance_window = "Sun:00:00-Sun:03:00"

  neptune_parameter_group_name = aws_neptune_parameter_group.custom.name
  apply_immediately           = true
}

# Security group restricting access to the example subnet only
resource "aws_security_group" "neptune_access" {
  name_prefix = "neptune-access-${random_id.suffix.hex}"
  vpc_id      = aws_vpc.neptune.id

  ingress {
    from_port       = 8182
    to_port         = 8182
    protocol        = "tcp"
    cidr_blocks     = [aws_subnet.neptune.cidr_block]
    description     = "Neptune access from example subnet only"
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Attach security group to cluster instances
resource "aws_neptune_cluster_instance" "example_secondary" {
  identifier         = "neptune-instance-secondary-${random_id.suffix.hex}"
  cluster_identifier = aws_neptune_cluster.example.id
  instance_class     = "db.t3.medium"
  engine             = "neptune"
  preferred_maintenance_window = "Sun:00:00-Sun:03:00"

  neptune_parameter_group_name = aws_neptune_parameter_group.custom.name
  apply_immediately           = true
}

resource "aws_neptune_subnet_group" "example" {
  name       = "neptune-subnet-group-${random_id.suffix.hex}"
  subnet_ids = [aws_subnet.neptune.id]
}

resource "aws_neptune_cluster" "example_complete" {
  cluster_identifier              = "neptune-cluster-${random_id.suffix.hex}"
  engine                          = "neptune"
  backup_retention_period         = 1
  preferred_backup_window         = "07:00-09:00"
  skip_final_snapshot             = true
  iam_database_authentication_enabled = true
  vpc_security_group_ids          = [aws_security_group.neptune_access.id]

  cluster_parameter_group_name = aws_neptune_cluster_parameter_group.custom.id
  neptune_subnet_group_name    = aws_neptune_subnet_group.example.name
  apply_immediately           = true
}

