        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "codebuild_policy" {
  name = "codebuild-autograder-policy-${random_id.suffix.hex}"
  role = aws_iam_role.codebuild_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:*:*:*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:GetObjectVersion",
          "s3:PutObject",
          "s3:PutObjectAcl",
          "s3:DeleteObject"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "codecommit:GitPull"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = "github:token"
        Resource = "*"
        Condition = {
          StringEquals = {
            "aws:RequestTag/Autograder" = "true"
          }
        }
      }
    ]
  })
}

resource "aws_s3_bucket" "autograder_artifacts" {
  bucket = "autograder-artifacts-${random_id.suffix.hex}"
}

resource "aws_s3_bucket_versioning" "autograder_artifacts" {
  bucket = aws_s3_bucket.autograder_artifacts.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_public_access_block" "autograder_artifacts" {
  bucket = aws_s3_bucket.autograder_artifacts.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

resource "aws_codebuild_source_credential" "github" {
  auth {
    type     = "PERSONAL_ACCESS_TOKEN"
    resource = "GITHUB"
  }
}

resource "aws_codebuild_project" "autograder" {
  name          = "course-autograder-${random_id.suffix.hex}"
  description   = "Autograding system for CS course"
  service_role  = aws_iam_role.codebuild_role.arn
  artifacts {
    type = "S3"
    name = "autograder-output"
    location = aws_s3_bucket.autograder_artifacts.bucket
  }

  environment {
    compute_type    = "BUILD_GENERAL1_SMALL"
    image           = "aws/codebuild/standard:7.0"
    type            = "LINUX_CONTAINER"
    privileged_mode = true
  }

  source {
    type     = "GITHUB"
    location = "https://github.com/your-org/course-repo.git" # Replace with course repo
  }

  buildspec = <<EOF
version: 0.2

phases:
  install:
    runtime-versions:
      python: 3.9
      java: corretto17
      nodejs: 18
    commands:
      - pip install pytest coverage flake8
      - npm install -g mocha
  pre_build:
    commands:
      - echo "Checking out student repo..."
      - git clone $STUDENT_REPO_URL student-submission
      - cd student-submission
      - git checkout $STUDENT_BRANCH
  build:
    commands:
      - echo "Running tests..."
      - pytest tests/ --junitxml=test-results.xml || true
      - coverage run --source=. main.py && coverage xml
      - flake8 . --exit-zero
      - echo "GRADE: $(( $(grep -c 'passed' test-results.xml || echo 0) * 10 ))/100" > grade.txt
  post_build:
    commands:
      - echo "Uploading results..."
      - aws s3 cp test-results.xml s3://${aws_s3_bucket.autograder_artifacts.bucket}/$STUDENT_REPO_URL/
      - aws s3 cp coverage.xml s3://${aws_s3_bucket.autograder_artifacts.bucket}/$STUDENT_REPO_URL/
      - aws s3 cp grade.txt s3://${aws_s3_bucket.autograder_artifacts.bucket}/$STUDENT_REPO_URL/
EOF

  tags = {
    Purpose = "Autograder"
  }
}

reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

resource "aws_s3_bucket" "artifact_bucket" {
  bucket_prefix = "artifact-bucket-"
}

resource "aws_codebuild_project" "autograder_build" {
  name         = "autograder_build"
  service_role = aws_iam_role.autograder_build_role.arn

  artifacts {
    type     = "S3"
    location = aws_s3_bucket.artifact_bucket.arn
    name     = "results.zip" # include this
  }

  environment { # arguments required, exact value not specified
    compute_type = "BUILD_GENERAL1_SMALL"
    image        = "aws/codebuild/standard:7.0-24.10.29"
    type         = "LINUX_CONTAINER"
  }

  source {
    type            = "GITHUB"
    git_clone_depth = 1 # good to have, not required
    location        = "github.com/source-location"
  }
}

resource "aws_iam_role" "autograder_build_role" {
  assume_role_policy = data.aws_iam_policy_document.autograder_build_policy_assume.json
}

data "aws_iam_policy_document" "autograder_build_policy_assume" {
  statement {
    actions = ["sts:AssumeRole"]

    principals {
      type        = "Service"
      identifiers = ["codebuild.amazonaws.com"]
    }
  }

}

data "aws_iam_policy_document" "autograder_build_policy" {
  statement {
    effect = "Allow"
    actions = [
      "ec2:DescribeSubnets",
      "ec2:DescribeSecurityGroups",
      "ec2:DescribeVpcs"
    ]
    resources = [
      "*"
    ]
  }
}

resource "aws_iam_policy" "autograder_build_policy" {
  name        = "lambda_policy"
  description = "Grants permissions to Lambda to describe vpc, subnet, security group"

  policy = data.aws_iam_policy_document.autograder_build_policy.json
}

resource "aws_iam_role_policy_attachment" "lambda_policy_attach" {
  role       = aws_iam_role.autograder_build_role.name
  policy_arn = aws_iam_policy.autograder_build_policy.arn
}

