    type      = "S3"
    location  = aws_s3_bucket.autograder.bucket
    buildspec = "buildspec.yml"
  }

  tags = {
    Project = "CS-Autograder"
  }
}

# CloudWatch log group for CodeBuild
resource "aws_cloudwatch_log_group" "autograder" {
  name              = "/aws/codebuild/cs-autograder-${random_id.suffix.hex}"
  retention_in_days = 30
}

# Example buildspec.yml content (would be uploaded to S3 separately)
# This clones GitHub repo, runs tests, and stores results
resource "aws_s3_object" "buildspec" {
  bucket = aws_s3_bucket.autograder.bucket
  key    = "buildspec.yml"
  content = yamlencode({
    version = "0.2"

    phases = {
      install = {
        commands = [
          "pip install -r requirements.txt",
          "apt-get update -y",
          "apt-get install -y git python3 python3-pip"
        ]
      }

      pre_build = {
        commands = [
          "echo Installing test dependencies...",
          "pip install pytest coverage"
        ]
      }

      build = {
        commands = [
          "echo Running autograder...",
          "git clone $GITHUB_REPO_URL student-submission",
          "cd student-submission",
          "pytest tests/ --junitxml=test-results.xml --cov=src",
          "coverage xml",
          "echo Grading complete"
        ]
      }

      post_build = {
        commands = [
          "aws s3 cp test-results.xml s3://$S3_BUCKET/grades/$STUDENT_ID/",
          "aws s3 cp coverage.xml s3://$S3_BUCKET/grades/$STUDENT_ID/",
          "echo Results uploaded"
        ]
      }
    }

    reports = {
      pytest_report = {
        files = ["test-results.xml"]
        base-directory = "./student-submission"
      }
    }
  })
}

