```hcl
# Random suffix for unique resource names
resource "random_id" "suffix" {
  byte_length = 4
}

# S3 bucket for storing student submissions, grading outputs, and build artifacts
resource "aws_s3_bucket" "autograder" {
  bucket = "cs-autograder-${random_id.suffix.hex}"
}

resource "aws_s3_bucket_versioning" "autograder" {
  bucket = aws_s3_bucket.autograder.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_public_access_block" "autograder" {
  bucket = aws_s3_bucket.autograder.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# IAM role for CodeBuild with necessary permissions
resource "aws_iam_role" "codebuild_role" {
  name = "cs-autograder-codebuild-${random_id.suffix.hex}"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

# IAM policy for CodeBuild role
resource "aws_iam_role_policy" "codebuild_policy" {
  name = "cs-autograder-codebuild-policy-${random_id.suffix.hex}"
  role = aws_iam_role.codebuild_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:*:*:*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:PutObjectAcl",
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.autograder.arn,
          "${aws_s3_bucket.autograder.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "codebuild:BatchGetBuilds",
          "codebuild:StartBuild"
        ]
        Resource = "*"
      }
    ]
  })
}

# CodeBuild service role attachment
resource "aws_iam_role_policy_attachment" "codebuild_service_role" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = "arn:aws:iam::aws:policy/CodeBuildServiceRole"
}

# S3 bucket for CodeBuild artifacts
resource "aws_s3_bucket" "codebuild_artifacts" {
  bucket = "cs-autograder-artifacts-${random_id.suffix.hex}"
}

resource "aws_s3_bucket_public_access_block" "codebuild_artifacts" {
  bucket = aws_s3_bucket.codebuild_artifacts.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# CodeBuild project for autograding
resource "aws_codebuild_project" "autograder" {
  name          = "cs-autograder-${random_id.suffix.hex}"
  description   = "CS Course Autograding System"
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "CODEPIPELINE" # Can be changed to S3 for simple deployments
  }

  environment {
    compute_type    = "BUILD_GENERAL1_SMALL"
    image           = "aws/codebuild/standard:5.0"
    type            = "LINUX_CONTAINER"
    privileged_mode = true

    environment_variable {
      name  = "S3_BUCKET"
      value = aws_s3_bucket.autograder.bucket
    }

    environment_variable {
      name  = "GRADING_OUTPUT_PREFIX"
      value = "grades/"
    }
  }

  source {
    type      = "S3"
    location  = aws_s3_bucket.autograder.bucket
    buildspec = "buildspec.yml"
  }

  tags = {
    Project = "CS-Autograder"
  }
}

# CloudWatch log group for CodeBuild
resource "aws_cloudwatch_log_group" "autograder" {
  name              = "/aws/codebuild/cs-autograder-${random_id.suffix.hex}"
  retention_in_days = 30
}

# Example buildspec.yml content (would be uploaded to S3 separately)
# This clones GitHub repo, runs tests, and stores results
resource "aws_s3_object" "buildspec" {
  bucket = aws_s3_bucket.autograder.bucket
  key    = "buildspec.yml"
  content = yamlencode({
    version = "0.2"

    phases = {
      install = {
        commands = [
          "pip install -r requirements.txt",
          "apt-get update -y",
          "apt-get install -y git python3 python3-pip"
        ]
      }

      pre_build = {
        commands = [
          "echo Installing test dependencies...",
          "pip install pytest coverage"
        ]
      }

      build = {
        commands = [
          "echo Running autograder...",
          "git clone $GITHUB_REPO_URL student-submission",
          "cd student-submission",
          "pytest tests/ --junitxml=test-results.xml --cov=src",
          "coverage xml",
          "echo Grading complete"
        ]
      }

      post_build = {
        commands = [
          "aws s3 cp test-results.xml s3://$S3_BUCKET/grades/$STUDENT_ID/",
          "aws s3 cp coverage.xml s3://$S3_BUCKET/grades/$STUDENT_ID/",
          "echo Results uploaded"
        ]
      }
    }

    reports = {
      pytest_report = {
        files = ["test-results.xml"]
        base-directory = "./student-submission"
      }
    }
  })
}
```

