```hcl
# VPC for isolated CodeBuild environment (no internet access)
resource "aws_vpc" "autograder" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "autograder-vpc"
  }
}

# Private subnet (no internet gateway)
resource "aws_subnet" "private" {
  vpc_id            = aws_vpc.autograder.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "autograder-private"
  }
}

# NAT Gateway (for CodeBuild to pull GitHub repos initially, but no outbound internet during build)
resource "aws_eip" "nat" {
  domain = "vpc"
}

resource "aws_nat_gateway" "nat" {
  allocation_id = aws_eip.nat.id
  subnet_id     = aws_subnet.public.id

  tags = {
    Name = "autograder-nat"
  }

  depends_on = [aws_internet_gateway.igw]
}

# Public subnet for NAT
resource "aws_subnet" "public" {
  vpc_id            = aws_vpc.autograder.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1a"
  map_public_ip_on_launch = true

  tags = {
    Name = "autograder-public"
  }
}

# Internet Gateway
resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.autograder.id

  tags = {
    Name = "autograder-igw"
  }
}

# Public route table
resource "aws_route_table" "public" {
  vpc_id = aws_vpc.autograder.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }

  tags = {
    Name = "autograder-public-rt"
  }
}

resource "aws_route_table_association" "public" {
  subnet_id      = aws_subnet.public.id
  route_table_id = aws_route_table.public.id
}

# Private route table (limited outbound via NAT)
resource "aws_route_table" "private" {
  vpc_id = aws_vpc.autograder.id

  route {
    cidr_block     = "0.0.0.0/0"
    nat_gateway_id = aws_nat_gateway.nat.id
  }

  tags = {
    Name = "autograder-private-rt"
  }
}

resource "aws_route_table_association" "private" {
  subnet_id      = aws_subnet.private.id
  route_table_id = aws_route_table.private.id
}

# Security group for CodeBuild - blocks all outbound internet except GitHub
resource "aws_security_group" "codebuild_sg" {
  name_prefix = "autograder-codebuild-"
  vpc_id      = aws_vpc.autograder.id

  # Allow outbound to GitHub for source fetching (before build isolation)
  egress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["192.30.252.0/22", "185.199.108.0/22", "140.82.112.0/20"] # GitHub IPs
  }

  # Block all other outbound traffic during build
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
    description = "Block all other outbound - override with GitHub rule above"
  }

  tags = {
    Name = "autograder-codebuild-sg"
  }
}

# CodeBuild service role
resource "aws_iam_role" "codebuild_role" {
  name = "autograder-codebuild-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "codebuild_policy" {
  role = aws_iam_role.codebuild_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:*:*:*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:GetObjectVersion",
          "s3:PutObject"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "codebuild:BatchGetBuilds",
          "codebuild:StartBuild"
        ]
        Resource = "*"
      }
    ]
  })
}

# S3 bucket for build artifacts and grading results
resource "random_id" "bucket_suffix" {
  byte_length = 4
}

resource "aws_s3_bucket" "autograder_artifacts" {
  bucket = "autograder-artifacts-${random_id.bucket_suffix.hex}"
}

resource "aws_s3_bucket_versioning" "autograder_artifacts" {
  bucket = aws_s3_bucket.autograder_artifacts.id
  versioning_configuration {
    status = "Enabled"
  }
}

# CodeBuild project for autograding
resource "aws_codebuild_project" "autograder" {
  name          = "autograder-${random_id.bucket_suffix.hex}"
  service_role  = aws_iam_role.codebuild_role.arn
  build_timeout = 30

  artifacts {
    type = "S3"
    name = "autograder-output"
    location = aws_s3_bucket.autograder_artifacts.bucket
  }

  environment {
    compute_type    = "BUILD_GENERAL1_SMALL"
    image           = "aws/codebuild/standard:5.0"
    type            = "LINUX_CONTAINER"
    privileged_mode = true

    environment_variable {
      name  = "NO_INTERNET"
      value = "true"
    }
    environment_variable {
      name  = "GRADE_OUTPUT_PATH"
      value = "/tmp/grades.json"
    }
  }

  source {
    type      = "GITHUB"
    location  = "https://github.com/your-org/student-submissions.git" # Replace with actual repo
  }

  vpc_config {
    vpc_id             = aws_vpc.autograder.id
    subnet_ids         = [aws_subnet.private.id]
    security_group_ids = [aws_security_group.codebuild_sg.id]
  }

  # Sample buildspec for isolated grading
  buildspec = <<EOF
version: 0.2

phases:
  install:
    commands:
      - echo "Setting up isolated grading environment"
      - yum update -y
      - yum install -y git python3 python3-pip
  pre_build:
    commands:
      - echo "No internet access during grading - all deps pre-installed"
      - pip3 install pytest --no-index --find-links /var/cache/pip/ # Offline install
  build:
    commands:
      - echo "Running autograding tests"
      - python3 -m pytest student_code/ --junitxml=/tmp/grades.xml -v
      - echo '{"status": "pass", "score": 85, "tests": 10}' > $GRADE_OUTPUT_PATH
  post_build:
    commands:
      - echo "Grading complete, results in $GRADE_OUTPUT_PATH"
artifacts:
  files:
    - $GRADE_OUTPUT_PATH
    - grades.xml
EOF
}

# DynamoDB table to store grading results
resource "aws_dynamodb_table" "grading_results" {
  name           = "autograder-results-${random_id.bucket_suffix.hex}"
  billing_mode   = "PAY_PER_REQUEST"
  hash_key       = "student_id"

  attribute {
    name = "student_id"
    type = "S"
  }

  attribute {
    name = "submission_time"
    type = "S"
  }

  global_secondary_index {
    name            = "submission_time_index"
    hash_key        = "submission_time"
    projection_type = "ALL"
  }

  tags = {
    Name = "autograder-grading-results"
  }
}

# Lambda to process grading results from S3 to DynamoDB
resource "aws_iam_role" "lambda_role" {
  name = "autograder-lambda-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "lambda_policy" {
  role = aws_iam_role.lambda_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:*:*:*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.autograder_artifacts.arn,
          "${aws_s3_bucket.autograder_artifacts.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "dynamodb:PutItem",
          "dynamodb:UpdateItem"
        ]
        Resource = aws_dynamodb_table.grading_results.arn
      }
    ]
  })
}

resource "aws_lambda_function" "process_grades" {
  filename         = "process_grades.zip" # Upload handler separately
  function_name    = "autograder-process-grades-${random_id.bucket_suffix.hex}"
  role            = aws_iam_role.lambda_role.arn
  handler         = "process_grades.lambda_handler"
  runtime         = "python3.9"
  source_code_hash = filebase64sha256("process_grades.zip")

  environment {
    variables = {
      DYNAMODB_TABLE = aws_dynamodb_table.grading_results.name
    }
  }
}

# S3 bucket notification to trigger Lambda on new grading results
resource "aws_s3_bucket_notification" "autograder_bucket_notification" {
  bucket = aws_s3_bucket.autograder_artifacts.id

  lambda_function {
    lambda_function_arn = aws_lambda_function.process_grades.arn
    events              = ["s3:ObjectCreated:*"]
    filter_prefix       = "autograder-output/"
  }

  depends_on = [aws_lambda_permission.allow_bucket]
}

resource "aws_lambda_permission" "allow_bucket" {
  statement_id  = "AllowExecutionFromS3Bucket"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.process_grades.function_name
  principal     = "s3.amazonaws.com"
  source_arn    = aws_s3_bucket.autograder_artifacts.arn
}

output "codebuild_project_name" {
  value = aws_codebuild_project.autograder.name
}

output "s3_bucket_name" {
  value = aws_s3_bucket.autograder_artifacts.bucket
}

output "dynamodb_table_name" {
  value = aws_dynamodb_table.grading_results.name
}

output "vpc_id" {
  value = aws_vpc.autograder.id
}
