```hcl
# VPC with private subnets for isolation (no internet access)
resource "aws_vpc" "autograde" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "autograde-vpc"
  }
}

resource "aws_subnet" "private" {
  count = 2

  vpc_id            = aws_vpc.autograde.id
  cidr_block        = "10.0.${count.index + 1}.0/24"
  availability_zone = element(data.aws_availability_zones.available.names, count.index)

  tags = {
    Name = "autograde-private-${count.index + 1}"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

# S3 bucket for storing student submissions and grading results
resource "aws_s3_bucket" "autograde" {
  bucket = "autograde-${random_id.suffix.hex}"
}

resource "aws_s3_bucket_versioning" "autograde" {
  bucket = aws_s3_bucket.autograde.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_public_access_block" "autograde" {
  bucket = aws_s3_bucket.autograde.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# IAM role for CodeBuild with minimal permissions
resource "aws_iam_role" "codebuild_role" {
  name = "autograde-codebuild-role-${random_id.suffix.hex}"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "codebuild_s3_policy" {
  name = "autograde-codebuild-s3-policy"
  role = aws_iam_role.codebuild_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:GetBucketVersioning"
        ]
        Resource = [
          "${aws_s3_bucket.autograde.arn}/*"
        ]
      }
    ]
  })
}

# CodeBuild project for isolated code execution
resource "aws_codebuild_project" "autograde" {
  name          = "autograde-${random_id.suffix.hex}"
  description   = "Autograding system for CS course submissions"
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type    = "BUILD_GENERAL1_SMALL"
    image           = "aws/codebuild/amazonlinux2-x86_64-standard:5.0"
    type            = "LINUX_CONTAINER"
    privileged_mode = false  # No privileged mode for security

    environment_variable {
      name  = "S3_BUCKET"
      value = aws_s3_bucket.autograde.bucket
    }
    environment_variable {
      name  = "NO_INTERNET"
      value = "true"
    }
  }

  source {
    type = "NO_SOURCE"
    # GitHub integration would be configured via webhook/API in production
  }

  vpc_config {
    vpc_id             = aws_vpc.autograde.id
    subnet_ids         = aws_subnet.private[*].id
    security_group_ids = [aws_security_group.codebuild.id]
  }

  # Buildspec template - downloads submission from S3, runs tests in isolated env, uploads results
  buildspec = <<-EOF
    version: 0.2

    env:
      variables:
        S3_BUCKET: "$S3_BUCKET"
        SUBMISSION_ID: "$SUBMISSION_ID"

    phases:
      pre_build:
        commands:
          - echo "Setting up isolated environment"
          - yum update -y
          - yum install -y git gcc python3 python3-pip docker
          - systemctl start docker

      build:
        commands:
          - echo "Downloading submission from S3"
          - aws s3 cp "s3://$S3_BUCKET/submissions/$SUBMISSION_ID.zip" submission.zip
          - unzip submission.zip -d /tmp/submission
          - echo "Running tests in isolated container (no network)"
          - docker run --network none --rm -v /tmp/submission:/code -w /code python:3.9-slim python -m pytest tests/ --junitxml=/tmp/results.xml || true
          - echo "Uploading results"
          - aws s3 cp /tmp/results.xml "s3://$S3_BUCKET/results/$SUBMISSION_ID.xml"
          - aws s3 cp /tmp/submission/test_output.log "s3://$S3_BUCKET/logs/$SUBMISSION_ID.log"

      post_build:
        commands:
          - echo "Cleanup"
          - rm -rf /tmp/submission submission.zip
  EOF
}

# Security group for CodeBuild (no outbound internet)
resource "aws_security_group" "codebuild" {
  name_prefix = "autograde-codebuild-"
  vpc_id      = aws_vpc.autograde.id

  egress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]  # Only VPC internal traffic
  }

  tags = {
    Name = "autograde-codebuild"
  }
}

# Random suffix for unique resource names
resource "random_id" "suffix" {
  byte_length = 4
}

# S3 bucket policy to allow CodeBuild access
resource "aws_s3_bucket_policy" "autograde" {
  bucket = aws_s3_bucket.autograde.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect    = "Allow"
        Principal = {
          AWS = aws_iam_role.codebuild_role.arn
        }
        Action   = ["s3:GetObject", "s3:PutObject"]
        Resource = "${aws_s3_bucket.autograde.arn}/*"
      }
    ]
  })
}
```

This configuration creates a complete autograding system with:

1. **Isolated VPC** - Private subnets with no internet gateway
2. **S3 bucket** - Stores submissions (`submissions/`) and results (`results/`, `logs/`)
3. **CodeBuild project** - Executes code in Docker containers with `--network none` (no internet)
4. **Restricted security group** - No outbound internet access
5. **Minimal IAM permissions** - Only S3 read/write access
6. **Automated workflow** - Download → Test → Upload results → Cleanup

**Usage**: Upload student GitHub zip to `s3://bucket/submissions/{submission_id}.zip` and trigger CodeBuild with `SUBMISSION_ID` environment variable. Results appear in `results/` and `logs/`.

