# Lambda code for random cat selection
data "archive_file" "random_cat" {
  type        = "zip"
  output_path = "/tmp/random_cat.zip"

  source {
    content = <<EOF
import json
import boto3
import random
import urllib.parse

s3 = boto3.client('s3')

def lambda_handler(event, context):
    bucket_name = event['BUCKET_NAME']

    # List objects in bucket
    response = s3.list_objects_v2(Bucket=bucket_name)

    if 'Contents' not in response or len(response['Contents']) == 0:
        return {
            'statusCode': 404,
            'body': json.dumps({'error': 'No cat images found'})
        }

    # Pick random object
    random_obj = random.choice(response['Contents'])
    object_key = random_obj['Key']

    # Generate presigned URL
    url = s3.generate_presigned_url(
        'get_object',
        Params={'Bucket': bucket_name, 'Key': object_key},
        ExpiresIn=3600
    )

    return {
        'statusCode': 200,
        'headers': {
            'Content-Type': 'application/json',
            'Access-Control-Allow-Origin': '*'
        },
        'body': json.dumps({
            'image_url': url,
            'key': object_key
        })
    }
EOF
    filename = "random_cat.py"
  }
}

# API Gateway
resource "aws_apigatewayv2_api" "cat_app" {
  name          = "cat-app-api-${random_id.suffix.hex}"
  protocol_type = "HTTP"
}

resource "aws_apigatewayv2_stage" "default" {
  api_id      = aws_apigatewayv2_api.cat_app.id
  name        = "$default"
  auto_deploy = true
}

# Lambda permission for API Gateway
resource "aws_lambda_permission" "api_gateway_random" {
  statement_id  = "AllowAPIGatewayInvoke"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.random_cat.function_name
  principal     = "apigateway.amazonaws.com"

  source_arn = "${aws_apigatewayv2_api.cat_app.execution_arn}/*/*"
}

# Random cat route
resource "aws_apigatewayv2_integration" "random_cat" {
  api_id             = aws_apigatewayv2_api.cat_app.id
  integration_type   = "AWS_PROXY"
  integration_uri    = aws_lambda_function.random_cat.invoke_arn
  integration_method = "POST"
}

resource "aws_apigatewayv2_route" "random_cat" {
  api_id    = aws_apigatewayv2_api.cat_app.id
  route_key = "GET /random"
  target    = "integrations/${aws_apigatewayv2_integration.random_cat.id}"
}

# CORS for API Gateway
resource "aws_apigatewayv2_route" "options_random" {
  api_id    = aws_apigatewayv2_api.cat_app.id
  route_key = "OPTIONS /{proxy+}"
  target    = "integrations/${aws_apigatewayv2_integration.cors.id}"
  api_key_required = false
}

resource "aws_apigatewayv2_integration" "cors" {
  api_id             = aws_apigatewayv2_api.cat_app.id
  integration_type   = "MOCK"
  integration_method = "POST"
  passthrough_behavior = "WHEN_NO_MATCH"

  request_templates = {
    "application/json" = "{"statusCode": 200}"
  }
}

# Output the important URLs
output "s3_bucket_name" {
  value = aws_s3_bucket.cat_images.bucket
}

output "api_gateway_url" {
  value = aws_apigatewayv2_stage.default.invoke_url
}

output "random_cat_endpoint" {
  value = "${aws_apigatewayv2_stage.default.invoke_url}/random"
}

reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}


provider "aws" {
  region  = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

resource "aws_dynamodb_table" "caas" {
  name           = "cat_names"
  hash_key       = "name"
  billing_mode   = "PAY_PER_REQUEST"

  attribute {
    name = "name"
    type = "S"
  }
}

resource "aws_s3_bucket" "caas" {
  bucket_prefix = "cat-image"
}

resource "aws_iam_role" "lambda_role" {
  name = "lambda_api_gateway_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "lambda_policy" {
  name   = "lambda_policy"
  role   = aws_iam_role.lambda_role.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "s3:GetObject",
          "s3:PutObject"
        ]
        Effect   = "Allow"
        Resource = "${aws_s3_bucket.caas.arn}/*"
      },
      {
        Action = [
          "dynamodb:PutItem"
        ]
        Effect   = "Allow"
        Resource = aws_dynamodb_table.caas.arn
      }
    ]
  })
}

resource "aws_api_gateway_rest_api" "caas" {
  name = "caas"
}

resource "aws_api_gateway_resource" "caas_cat" {
  rest_api_id = aws_api_gateway_rest_api.caas.id
  parent_id   = aws_api_gateway_rest_api.caas.root_resource_id
  path_part   = "cat"
}

resource "aws_api_gateway_method" "caas_cat_get" {
  rest_api_id   = aws_api_gateway_rest_api.caas.id
  resource_id   = aws_api_gateway_resource.caas_cat.id
  http_method   = "GET"
  authorization = "NONE"
}

resource "aws_api_gateway_method" "caas_cat_put" {
  rest_api_id   = aws_api_gateway_rest_api.caas.id
  resource_id   = aws_api_gateway_resource.caas_cat.id
  http_method   = "PUT"
  authorization = "NONE"
}

data "archive_file" "caas_cat" {
  type        = "zip"
  source_file = "./supplement/caas_cat.py"
  output_path = "./supplement/caas_cat.zip"
}

resource "aws_lambda_function" "caas_cat" {
  function_name = "caas_cat"
  role          = aws_iam_role.lambda_role.arn
  filename      = data.archive_file.caas_cat.output_path
  source_code_hash = data.archive_file.caas_cat.output_base64sha256
  handler       = "caas_cat.handler"
  runtime       = "python3.12"

  environment {
    variables = {
      CAAS_S3_BUCKET = "${aws_s3_bucket.caas.id}"
      DYNAMODB_TABLE_NAME = "${aws_dynamodb_table.caas.id}"
    }
  }
}

resource "aws_api_gateway_integration" "caas_cat_get" {
  rest_api_id             = aws_api_gateway_rest_api.caas.id
  resource_id             = aws_api_gateway_resource.caas_cat.id
  http_method             = aws_api_gateway_method.caas_cat_get.http_method
  type                    = "AWS_PROXY"
  integration_http_method = "GET"
  uri                     = aws_lambda_function.caas_cat.invoke_arn
}

resource "aws_api_gateway_integration" "caas_cat_put" {
  rest_api_id             = aws_api_gateway_rest_api.caas.id
  resource_id             = aws_api_gateway_resource.caas_cat.id
  http_method             = aws_api_gateway_method.caas_cat_put.http_method
