  api_id    = aws_apigatewayv2_api.cat_api.id
  route_key = "GET /random"
  target    = "integrations/${aws_apigatewayv2_integration.random.id}"
}

# Lambda permission for API Gateway
resource "aws_lambda_permission" "api_gateway" {
  statement_id  = "AllowAPIGatewayInvoke"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.cat_api.function_name
  principal     = "apigateway.amazonaws.com"
  source_arn    = "${aws_apigatewayv2_api.cat_api.execution_arn}/*"
}

# Output the API endpoint
