**Note:** You'll need to create a `cat_api.zip` file containing your Lambda function code. Here's a sample Python handler structure:

```python
# cat_api.py
import json
import boto3
import os
import uuid
import random
from urllib.parse import unquote_plus

s3 = boto3.client('s3')
bucket_name = os.environ['BUCKET_NAME']

def handler(event, context):
    http_method = event['requestContext']['http']['method']

    if http_method == 'POST' and event['rawPath'] == '/upload':
        return handle_upload(event)
    elif http_method == 'GET' and event['rawPath'] == '/random':
        return handle_random()
    else:
        return {'statusCode': 404}

def handle_upload(event):
    try:
        body = base64.b64decode(event['body'])
        key = f"cats/{uuid.uuid4()}.jpg"
        s3.put_object(Bucket=bucket_name, Key=key, Body=body, ContentType='image/jpeg')
        return {
            'statusCode': 200,
            'body': json.dumps({'message': 'Image uploaded successfully', 'key': key})
        }
    except Exception as e:
        return {'statusCode': 500, 'body': str(e)}

def handle_random():
    try:
        response = s3.list_objects_v2(Bucket=bucket_name, Prefix='cats/')
        if 'Contents' not in response:
            return {'statusCode': 404, 'body': 'No cat images found'}

        obj = random.choice(response['Contents'])
        url = f"https://{bucket_name}.s3.amazonaws.com/{obj['Key']}"
        return {
            'statusCode': 200,
            'headers': {'Content-Type': 'application/json'},
            'body': json.dumps({'image_url': url})
        }
    except Exception as e:
        return {'statusCode': 500, 'body': str(e)}
```

Zip this code as `cat_api.zip` and place it in your Terraform directory before running `terraform apply`.

