resource "aws_iam_role_policy_attachment" "ec2_backup_policy" {
  role       = aws_iam_role.ec2_backup_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSBackupServiceRolePolicyForBackup"
}

resource "aws_iam_instance_profile" "ec2_backup_profile" {
  name = "ec2-backup-profile-${random_id.suffix.hex}"
  role = aws_iam_role.ec2_backup_role.name
}

# EC2 instance
resource "aws_instance" "example" {
  ami           = "ami-0c02fb55956c7d316" # Amazon Linux 2 AMI (update for your region)
  instance_type = "t3.micro"
  iam_instance_profile = aws_iam_instance_profile.ec2_backup_profile.name

  tags = {
    Name = "backup-example-${random_id.suffix.hex}"
  }
}

# IAM role for AWS Backup
resource "aws_iam_role" "awsbackup_role" {
  name = "awsbackup-role-${random_id.suffix.hex}"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "backup.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "awsbackup_policy" {
  role       = aws_iam_role.awsbackup_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSBackupServiceRolePolicyForBackup"
}

resource "aws_iam_role_policy_attachment" "awsbackup_vault_policy" {
  role       = aws_iam_role.awsbackup_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSBackupVaultAccessPolicy"
}

# Backup vault
resource "aws_backup_vault" "example" {
  name = "example-vault-${random_id.suffix.hex}"

  encryption_configuration {
    key_arn = "arn:aws:kms:us-east-1:111122223333:key/1234abcd-12ab-34cd-56ef-1234567890ab" # Default AWS managed key or create custom KMS
  }
}

# Backup plan - daily at 12:00 AM UTC
resource "aws_backup_plan" "daily" {
  name = "daily-backup-plan-${random_id.suffix.hex}"

  rule {
    rule_name         = "daily-rule"
    target_vault_name = aws_backup_vault.example.name
    schedule          = "cron(0 0 * * ? *)" # 12:00 AM UTC daily

    lifecycle {
      delete_after = 30 # days
    }
  }

  # Assign the service role
  advanced_backup_setting {
    backup_options = {
      BackupType = "FULL"
    }
  }
}

