# Random suffix for unique resource names
resource "random_id" "suffix" {
  byte_length = 4
}

# S3 bucket for video content with website hosting (source for CloudFront)
resource "aws_s3_bucket" "video_content" {
  bucket = "video-streaming-${random_id.suffix.hex}"
}

resource "aws_s3_bucket_website_configuration" "video_content" {
  bucket = aws_s3_bucket.video_content.id

  index_document {
    suffix = "index.html"
  }

  error_document {
    key = "error.html"
  }
}

resource "aws_s3_bucket_acl" "video_content" {
  bucket = aws_s3_bucket.video_content.id
  acl    = "private"
}

resource "aws_s3_bucket_cors_configuration" "video_content" {
  bucket = aws_s3_bucket.video_content.id

  cors_rule {
    allowed_headers = ["*"]
    allowed_methods = ["GET", "HEAD"]
    allowed_origins = ["*"]
    expose_headers  = ["ETag"]
    max_age_seconds = 3000
  }
}

resource "aws_s3_bucket_policy" "video_content" {
  bucket = aws_s3_bucket.video_content.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "AllowCloudFront"
        Effect    = "Allow"
        Principal = {
          AWS = aws_cloudfront_origin_access_identity.video_content.iam_arn
        }
        Action   = "s3:GetObject"
        Resource = "${aws_s3_bucket.video_content.arn}/*"
      }
    ]
  })
}

# CloudFront Origin Access Identity for secure S3 access
resource "aws_cloudfront_origin_access_identity" "video_content" {
  comment = "OAI for video streaming bucket"
}

# CloudFront Distribution for global video delivery
resource "aws_cloudfront_distribution" "video_streaming" {
  origin {
    domain_name = aws_s3_bucket.video_content.bucket_regional_domain_name
    origin_id   = "S3-video-content"

    s3_origin_config {
      origin_access_identity = aws_cloudfront_origin_access_identity.video_content.cloudfront_access_identity_path
    }
  }

  enabled             = true
  is_ipv6_enabled     = true
  default_root_object = "index.html"

  aliases = ["streaming.example.com"]

  default_cache_behavior {
    allowed_methods  = ["DELETE", "GET", "HEAD", "OPTIONS", "PATCH", "POST", "PUT"]
    cached_methods   = ["GET", "HEAD"]
    target_origin_id = "S3-video-content"

    forwarded_values {
      query_string = false
      cookies {
        forward = "none"
      }
    }

    viewer_protocol_policy = "redirect-to-https"
    min_ttl                = 0
    default_ttl            = 3600
    max_ttl                = 86400
  }

  price_class = "PriceClass_100" # Global coverage (US/Europe/Asia)

  restrictions {
    geo_restriction {
      restriction_type = "none"
    }
  }

  viewer_certificate {
    cloudfront_default_certificate = true
  }

  # Custom error pages for graceful handling
  custom_error_response {
    error_code         = 404
    response_code      = 200
    response_page_path = "/error.html"
  }
}

# Route 53 Hosted Zone
resource "aws_route53_zone" "streaming" {
