    key                 = "Name"
    value               = "video-server-${random_id.suffix.hex}"
    propagate_at_launch = true
  }
}

# Route53 Hosted Zone
resource "aws_route53_zone" "video" {
  name = "video-streaming.${random_id.suffix.hex}.example.com"

  tags = {
    Name = "video-streaming-${random_id.suffix.hex}"
  }
}

# Route53 Record pointing to ALB
resource "aws_route53_record" "video" {
  zone_id = aws_route53_zone.video.zone_id
  name    = "streaming.video-streaming.${random_id.suffix.hex}.example.com"
  type    = "A"

  aliases {
    name                   = aws_lb.video.dns_name
    zone_id                = aws_lb.video.zone_id
    evaluate_target_health = true
  }
}

# Output ALB DNS name and Route53 domain
output "alb_dns_name" {
  value = aws_lb.video.dns_name
}

output "route53_domain" {
  value = aws_route53_record.video.fqdn
}
```

