  vpc_id = aws_vpc.main.id
  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.main.id
  }
  tags = {
    Name = "public-rt-${random_id.suffix.hex}"
  }
}

resource "aws_route_table_association" "public" {
  subnet_id      = aws_subnet.public.id
  route_table_id = aws_route_table.public.id
}

# Database Subnet Group (for RDS multi-AZ support)
resource "aws_db_subnet_group" "main" {
  name       = "mysql-subnet-group-${random_id.suffix.hex}"
  subnet_ids = [aws_subnet.public.id]

  tags = {
    Name = "mysql-subnet-group-${random_id.suffix.hex}"
  }
}

# Database Security Group
resource "aws_security_group" "database" {
  name_prefix = "mysql-sg-${random_id.suffix.hex}"
  vpc_id      = aws_vpc.main.id

  # Allow MySQL port 3306 from anywhere (adjust as needed for production)
  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # Allow all outbound
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "mysql-sg-${random_id.suffix.hex}"
  }
}

# MySQL RDS Instance
resource "aws_db_instance" "mysql" {
  identifier             = "mysql-${random_id.suffix.hex}"
  engine                 = "mysql"
  engine_version         = "8.0.43"  # Closest available to 8.4.3
  instance_class         = "db.t3.micro"
  allocated_storage      = 5
  storage_type           = "gp2"
  db_name                = "mydatabase"
  username               = "admin"
  password               = random_password.db.result
  db_subnet_group_name   = aws_db_subnet_group.main.name
  vpc_security_group_ids = [aws_security_group.database.id]
  publicly_accessible    = true
  skip_final_snapshot    = true
  final_snapshot_identifier = "mysql-final-snapshot-${random_id.suffix.hex}"
}

