```hcl
# Random suffix for unique naming
resource "random_id" "suffix" {
  byte_length = 4
}

# Random password for DB admin
resource "random_password" "db" {
  length  = 16
  special = true
}

# KMS Key for encryption
resource "aws_kms_key" "rds" {
  description             = "KMS key for RDS encryption"
  enable_key_rotation     = true
  deletion_window_in_days = 7
}

# Custom PostgreSQL parameter group
resource "aws_db_parameter_group" "postgres" {
  name   = "postgres15-${random_id.suffix.hex}"
  family = "postgres15"

  parameter {
    name  = "log_connections"
    value = "1"
  }

  parameter {
    name  = "log_disconnections"
    value = "1"
  }
}

# VPC for RDS (assuming default VPC or custom VPC setup)
data "aws_vpc" "default" {
  default = true
}

# Subnets for RDS subnet group (using default subnets)
data "aws_subnets" "default" {
  filter {
    name   = "vpc-id"
    values = [data.aws_vpc.default.id]
  }
}

# DB Subnet Group
resource "aws_db_subnet_group" "rds" {
  name       = "rds-${random_id.suffix.hex}"
  subnet_ids = data.aws_subnets.default.ids

  tags = {
    Name = "RDS Subnet Group"
  }
}

# Security Group for RDS
resource "aws_security_group" "rds" {
  name_prefix = "rds-postgres-${random_id.suffix.hex}"
  vpc_id      = data.aws_vpc.default.id

  ingress {
    description = "PostgreSQL access"
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/8"]  # Adjust to your VPC CIDR
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "RDS PostgreSQL SG"
  }
}

# RDS PostgreSQL Instance
resource "aws_db_instance" "postgres" {
  identifier             = "postgres15-${random_id.suffix.hex}"
  engine                 = "postgres"
  engine_version         = "15.4"
  instance_class         = "db.t3.medium"
  allocated_storage      = 50
  storage_type           = "gp3"
  storage_encrypted      = true
  kms_key_id             = aws_kms_key.rds.arn

  db_name  = "postgresdb"
  username = "postgresadmin"
  password = random_password.db.result

  vpc_security_group_ids      = [aws_security_group.rds.id]
  db_subnet_group_name        = aws_db_subnet_group.rds.name
  parameter_group_name        = aws_db_parameter_group.postgres.name
  multi_az                    = true
  backup_retention_period     = 7
  backup_window              = "03:00-04:00"
  maintenance_window         = "sun:04:00-sun:05:00"
  deletion_protection        = false
  skip_final_snapshot        = true
  final_snapshot_identifier  = "postgres15-${random_id.suffix.hex}-final"

  tags = {
    Name = "Secure PostgreSQL 15"
  }
}
```

