  cidr_block        = "10.0.2.0/24"
  availability_zone = data.aws_availability_zones.available.names[1]
  tags = {
    Name = "private-subnet-2-${random_id.suffix.hex}"
  }
}

resource "aws_db_subnet_group" "primary" {
  name       = "primary-subnet-group-${random_id.suffix.hex}"
  subnet_ids = [aws_subnet.private_1.id, aws_subnet.private_2.id]

  tags = {
    Name = "primary-subnet-group-${random_id.suffix.hex}"
  }
}

resource "aws_security_group" "rds" {
  name_prefix = "rds-sg-${random_id.suffix.hex}"
  vpc_id      = aws_vpc.primary.id

  ingress {
    description = "PostgreSQL access"
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "rds-security-group-${random_id.suffix.hex}"
  }
}

resource "aws_internet_gateway" "primary" {
  vpc_id = aws_vpc.primary.id

  tags = {
    Name = "primary-igw-${random_id.suffix.hex}"
  }
}

resource "aws_route_table" "public" {
  vpc_id = aws_vpc.primary.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.primary.id
  }

  tags = {
    Name = "public-rt-${random_id.suffix.hex}"
  }
}

resource "aws_route_table_association" "public_1" {
  subnet_id      = aws_subnet.private_1.id
  route_table_id = aws_route_table.public.id
}

resource "aws_route_table_association" "public_2" {
  subnet_id      = aws_subnet.private_2.id
  route_table_id = aws_route_table.public.id
}

resource "aws_db_instance" "postgres" {
  identifier              = "postgres-${random_id.suffix.hex}"
  engine                  = "postgres"
  engine_version          = "15.3"
  instance_class          = "db.t4g.micro"
  allocated_storage       = 200
  storage_type            = "gp2"
  publicly_accessible     = true
  db_subnet_group_name    = aws_db_subnet_group.primary.name
  vpc_security_group_ids  = [aws_security_group.rds.id]
  db_name                 = "postgresdb"
  username                = "postgres"
  password                = random_password.db.result
  skip_final_snapshot     = true
  backup_retention_period = 0

  tags = {
    Name = "postgres-${random_id.suffix.hex}"
  }
}

output "rds_endpoint" {
  description = "The endpoint for the PostgreSQL RDS instance"
  value       = aws_db_instance.postgres.endpoint
}
```

