```hcl
# Random suffix for unique naming
resource "random_id" "suffix" {
  byte_length = 4
}

# Random password for DB
resource "random_password" "db_master" {
  length  = 16
  special = true
}

# VPC
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "aurora-vpc-${random_id.suffix.hex}"
  }
}

# Subnets
resource "aws_subnet" "private_a" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
  tags = {
    Name = "aurora-private-a-${random_id.suffix.hex}"
  }
}

resource "aws_subnet" "private_b" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
  tags = {
    Name = "aurora-private-b-${random_id.suffix.hex}"
  }
}

# Subnet group for Aurora
resource "aws_db_subnet_group" "aurora" {
  name       = "aurora-subnet-group-${random_id.suffix.hex}"
  subnet_ids = [aws_subnet.private_a.id, aws_subnet.private_b.id]

  tags = {
    Name = "aurora-subnet-group-${random_id.suffix.hex}"
  }
}

# Security Group for DB
resource "aws_security_group" "aurora_sg" {
  name_prefix = "aurora-sg-${random_id.suffix.hex}"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    self        = true
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "aurora-sg-${random_id.suffix.hex}"
  }
}

# Security Group for RDS Proxy
resource "aws_security_group" "rds_proxy_sg" {
  name_prefix = "rds-proxy-sg-${random_id.suffix.hex}"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port       = 3306
    to_port         = 3306
    protocol        = "tcp"
    security_groups = [aws_security_group.aurora_sg.id]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "rds-proxy-sg-${random_id.suffix.hex}"
  }
}

# IAM Role for RDS Proxy
resource "aws_iam_role" "rds_proxy_role" {
  name = "rds-proxy-role-${random_id.suffix.hex}"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "rds.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy for Secrets Manager access
resource "aws_iam_role_policy" "rds_proxy_secrets_policy" {
  name = "rds-proxy-secrets-policy-${random_id.suffix.hex}"
  role = aws_iam_role.rds_proxy_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "secretsmanager:GetRandomPassword",
          "secretsmanager:GetSecretValue"
        ]
        Resource = aws_secretsmanager_secret.db_secret.arn
      }
    ]
  })
}

# Secrets Manager Secret
resource "aws_secretsmanager_secret" "db_secret" {
  name = "aurora-db-secret-${random_id.suffix.hex}"
}

resource "aws_secretsmanager_secret_version" "db_secret_version" {
  secret_id     = aws_secretsmanager_secret.db_secret.id
  secret_string = jsonencode({
    username = "admin"
    password = random_password.db_master.result
    engine   = "mysql"
    host     = aws_rds_cluster.aurora.endpoint
    port     = 3306
  })
}

# Aurora MySQL Cluster
resource "aws_rds_cluster" "aurora" {
  cluster_identifier      = "aurora-cluster-${random_id.suffix.hex}"
  engine                  = "aurora-mysql"
  engine_version          = "8.0.mysql_aurora.3.02.0"
  availability_zones      = ["us-east-1a", "us-east-1b"]
  database_name           = "auroradb"
  master_username         = "admin"
  manage_master_user_password = true
  master_user_secret {
    secret_arn = aws_secretsmanager_secret.db_secret.arn
  }
  db_subnet_group_name   = aws_db_subnet_group.aurora.name
  vpc_security_group_ids = [aws_security_group.aurora_sg.id]
  storage_encrypted      = true
  final_snapshot_identifier = "aurora-final-snapshot-${random_id.suffix.hex}"
  skip_final_snapshot    = false

  tags = {
    Name = "aurora-cluster-${random_id.suffix.hex}"
  }
}

# Aurora Cluster Instance
resource "aws_rds_cluster_instance" "aurora_instances" {
  count              = 2
  identifier         = "aurora-instance-${random_id.suffix.hex}-${count.index}"
  cluster_identifier = aws_rds_cluster.aurora.id
  instance_class     = "db.r6g.large"
  engine             = aws_rds_cluster.aurora.engine
  engine_version     = aws_rds_cluster.aurora.engine_version

  tags = {
    Name = "aurora-instance-${random_id.suffix.hex}-${count.index}"
  }
}

# RDS Proxy
resource "aws_db_proxy" "aurora_proxy" {
  name                   = "aurora-proxy-${random_id.suffix.hex}"
  debug_logging          = false
  engine_family          = "MYSQL"
  idle_client_timeout    = 1800
  require_tls            = true
  role_arn               = aws_iam_role.rds_proxy_role.arn
  vpc_security_group_ids = [aws_security_group.rds_proxy_sg.id]
  vpc_subnet_ids         = [aws_subnet.private_a.id, aws_subnet.private_b.id]

  auth {
    auth_scheme = "SECRETS"
    description = "aurora-proxy-auth"
    secret_arn  = aws_secretsmanager_secret.db_secret.arn
    iam_auth    = "DISABLED"
  }

  tags = {
    Name = "aurora-proxy-${random_id.suffix.hex}"
  }

  depends_on = [aws_iam_role_policy.rds_proxy_secrets_policy]
}

# RDS Proxy Target
resource "aws_db_proxy_target" "aurora_target" {
  db_proxy_name = aws_db_proxy.aurora.name
  target_type   = "rds"
  db_cluster_identifier = aws_rds_cluster.aurora.id
}
