# Lightsail Instance as origin
resource "aws_lightsail_instance" "origin" {
  name              = "distribution-origin-${random_id.suffix.hex}"
  availability_zone = "us-west-2a"
  blueprint_id      = "amazon_linux_2"
  bundle_id         = "nano_2_0"

  user_data = <<-EOF
    #!/bin/bash
    yum update -y
    yum install -y httpd
    systemctl start httpd
    systemctl enable httpd
    echo "<h1>Lightsail Origin Server</h1>" > /var/www/html/index.html
  EOF

  provision_static_ip = true
}

# Lightsail Distribution using the instance as origin
resource "aws_lightsail_distribution" "example" {
  name         = "example-distribution-${random_id.suffix.hex}"
  domain_name  = "example.com"
  origin {
    name       = "Origin"
    region_name = "us-west-2"
    protocol_policy = "http-only"
  }

  default_cache_behavior {
    behavior = "dont-cache"
  }

  is_enabled = true

  # Wait for instance to be ready before referencing its IP
  depends_on = [aws_lightsail_instance.origin]
}

# Get static IP of the instance for origin configuration
data "aws_lightsail_static_ip" "origin_ip" {
  name = aws_lightsail_instance.origin.static_ip
}

# Output for manual origin configuration (Lightsail distributions require manual origin IP setup in console)
output "origin_static_ip" {
  value = data.aws_lightsail_static_ip.origin_ip.ip_address
}

output "distribution_domain_name" {
  value = aws_lightsail_distribution.example.domain_name
}

output "instance_password" {
  value     = random_password.instance.result
  sensitive = true
}

