resource "aws_dlm_lifecycle_policy" "example" {
  description        = "Example DLM policy with Glacier vault integration"
  execution_role_arn = "arn:aws:iam::123456789012:role/AWSDataLifecycleManagerDefaultRole"
  state              = "ENABLED"

  policy_details {
    resource_types = ["VOLUME"]

    schedule {
      name                = "DailySnapshots"
      tags_to_add         = { "Environment" = "Production" }
      create_rule {
        interval      = 24
        interval_unit = "HOURS"
        times         = ["00:00"]
        location      = "AWS"
      }
      retain_rule {
        count = 7
      }
      copy_rule {
        interval      = 24
        interval_unit = "HOURS"
        times         = ["00:00"]
        target        = "REGION"
        target_tags   = { "Environment" = "Production" }
      }
    }

    parameters {
      exclude_boot_volume = false
    }
  }

  tags = {
    Environment = "Production"
  }
}

