  target_id        = aws_instance.example_a.id
  port             = 80
}

resource "aws_lb_target_group_attachment" "example_b" {
  target_group_arn = aws_lb_target_group.example.arn
  target_id        = aws_instance.example_b.id
  port             = 80
}
